(window.WISE_WORLD_Q = window.WISE_WORLD_Q || {}).sw = [
  { id:1, topic:"Lishe bora", emoji:"🍱",
    question:"Kwa nini ni muhimu kula kwa uwiano aina nyingi za chakula, kama wali, nyama, na mboga?",
    choices:["Kwa sababu tumbo hujaa haraka","Kwa sababu kila chakula kina kazi tofauti: baadhi huwa nishati ya kuendesha mwili, baadhi hujenga misuli na mifupa, na baadhi hudumisha hali ya mwili","Kwa sababu kula sana hukufanya ukimbie kwa kasi zaidi","Kwa sababu chakula huonekana cha rangirangi na kizuri"],
    answerIndex:1,
    explanation:"Kila chakula kina nguvu muhimu tofauti iitwayo “kirutubisho”. Kwa mfano, wali, mkate, na mizizi huwa “nishati inayoendesha mwili wako”, kama vile mkokoteni unavyohitaji mafuta na mnyama wa kazi anavyohitaji malisho. Nyama, samaki, na kunde huwa “malighafi inayojenga misuli, damu, na mifupa yako”. Na mboga na matunda huwa “ngao inayolinda mwili wako dhidi ya magonjwa na kudumisha hali yake”. Kama hata kimoja kati ya hivi kikipungua, unaweza kukosa nguvu, kuugua kwa urahisi zaidi, au kuacha kukua mkubwa na hodari. Kula aina nyingi za chakula ni kama kuunda timu yenye nguvu zaidi ndani ya mwili wako mwenyewe." },
  { id:2, topic:"Usingizi na ubongo", emoji:"😴",
    question:"Kulala vizuri usiku ni jambo zuri sana kwa ubongo wako. Hufanya jambo gani jema?",
    choices:["Ubongo hupanga vizuri matukio na maarifa ya siku na kuyahifadhi kama kumbukumbu","Unapolala, ubongo wako hutoweka kabisa","Hutahitaji kula kifungua kinywa siku inayofuata","Unapata kichezeo unachotaka ndani ya ndoto"],
    answerIndex:0,
    explanation:"Mtu anapolala, ubongo haupumziki tu. Huchukua kiasi kikubwa cha taarifa za siku — ulichokiona, ulichokipitia katika maisha ya kila siku, mambo mapya uliyofundishwa — na kuyapanga kichwani mwako katika makasha kama “hii ni kumbukumbu muhimu” na “haya ni maarifa ya lazima”, ukipanga kila kitu vizuri. Usipolala vizuri, muda wa kupanga haya haukutoshi, hivyo waweza kusahau uliyojifunza kwa shida, au kuhisi kichwa kizito na kushindwa kuzingatia siku inayofuata. Ili kuwa hodari zaidi katika masomo na kazi pia, usingizi wa usiku ni wa lazima kabisa kama muda wa matengenezo ya ubongo." },
  { id:3, topic:"Nguvu ya kifungua kinywa", emoji:"🍞",
    question:"Usipokula kifungua kinywa baada ya kuamka, mwili na ubongo wako hupatwa na nini wakati wa asubuhi?",
    choices:["Mwili wako huwa mwepesi na kuruka juu zaidi kuliko kawaida","Ubongo wako hupungukiwa nishati (glukosi), hivyo kichwa hakifanyi kazi vizuri, unakuwa mkali wa hasira na bila nguvu","Macho yako huona vizuri zaidi","Hakuna kinachobadilika"],
    answerIndex:1,
    explanation:"Baada ya kulala usingizi mzito usiku kucha, ubongo na mwili wako uliopumzika huamka karibu kama betri iliyokwisha chaji, nishati yake tupu. Ili kufanya kazi, ubongo huhitaji nishati iitwayo “glukosi”, lakini mwili hauwezi kuihifadhi nyingi. Kwa hiyo, ukianza kutembea bila kula kifungua kinywa, hakuna mafuta yanayofika ubongoni mwako: maneno muhimu hayaingii kichwani, na waweza kuwa mkali kwa mambo madogo na hata kugombana na rafiki au familia. Kifungua kinywa ni “swichi ya moyo” inayokuwezesha kuanza siku ukiwa umejaa nguvu na tabasamu." },
  { id:4, topic:"Hila ya mgeni", emoji:"🚶",
    question:"Mtu usiyemjua anakuambia: “Mama yako amepata ajali na amepelekwa hospitali, kwa hiyo njoo nami mahali pa mbali.” Utafanya nini?",
    choices:["Kwa kuwa una wasiwasi kuhusu familia yako, unaharakisha na kwenda na mtu huyo","Usiende kamwe. Ondoka mahali hapo mara moja na kimbilia mahali salama penye watu wengi, kama soko au uwanja, na uombe msaada kwa watu wazima walio karibu","Unatembea pamoja na mtu huyo kutafuta hospitali","Unasimama pale pale ukilia"],
    answerIndex:1,
    explanation:"Huu ni “uongo” ambao watu wabaya hutumia kuwadanganya watoto na kuwachukua (uhalifu kama utekaji nyara na kazi za kulazimishwa). Mtu wa familia anapojeruhiwa vibaya kweli, mtu unayemwamini — mtu wa kijiji chako, mwalimu, au ndugu — atazungumza nawe moja kwa moja. Mgeni hatakuja kukuchukua peke yake kamwe. Hata uwe na wasiwasi au hofu kiasi gani, kwanza shika kanuni hii: “usimfuate mgeni kamwe”. Kisha ondoka mahali hapo mara moja na kimbilia mahali salama penye watu wengi na sauti yako iweze kuwafikia, kama soko au uwanja, na uombe msaada kwa watu wazima walio karibu nawe." },
  { id:5, topic:"Piga kelele uombe msaada", emoji:"📢",
    question:"Unapotembea nje, mgeni anakushika mkono kwa nguvu au anajaribu kukuchukua. Utafanya nini?",
    choices:["Unaogopa kumkasirisha, kwa hiyo unatii kimyakimya","Piga kelele kutoka ndani ya tumbo “Msaada! Moto!”, jitahidi kupambana na kupinga, na ukimbie kwa nguvu zako zote kuelekea penye watu wengi","Unachuchumaa pale pale na kufumba macho","Unamuuliza: “Tunakwenda wapi?”"],
    answerIndex:1,
    explanation:"Unapokaribia kuwa hatarini, kunyamaza kwa hofu hufanya watu wa karibu wasitambue, na hali huwa hatari sana. Watu wabaya huchukia zaidi ya yote “kelele kubwa” na “kuonekana na watu hivyo uovu wao kufichuliwa”. Ukishikwa mkono, usione haya: piga kelele kutoka ndani ya tumbo “Msaada!” na “Moto!”, maneno yanayofanya kila mtu ageuke kutazama. Kisha pambana ujikwamue mkono na ukimbie kwa nguvu zako zote kuelekea mahali penye watu wengi. Kupaza sauti ni silaha yenye nguvu ya kutuma ishara ya dharura kwa ulimwengu unaokuzunguka." },
  { id:6, topic:"Kuvuka barabara", emoji:"🚸",
    question:"Unapovuka barabara ambayo magari, pikipiki, au mikokoteni ya farasi hupita, ni njia ipi sahihi ya kuvuka kwa usalama?",
    choices:["Unaanza kukimbia haraka bila kuthibitisha kama gari linakuja","Simama kwanza, tazama vizuri kulia na kushoto, na uvuke tu baada ya kuhakikisha kuwa magari yanayokaribia yamepita kabisa au yamesimama","Funga macho, hesabu hadi 10, kisha vuka","Subiri tu watu wengine wavuke"],
    answerIndex:1,
    explanation:"Unapovuka barabara, ni hatari sana kudhani “dereva hakika ataniona na kusimama”. Dereva anaweza kuwa anatazama upande mwingine, au pengine hakukuona. Unapovuka, daima weka miguu yako imara chini na usimame, na tazama kulia na kushoto mara kwa mara. Kisha subiri gari linalokaribia lipite kabisa, au hakikisha limesimama wazi mbele yako kabisa na dereva anakuona, ndipo uvuke moja kwa moja kwa usalama. Tabia ya kuthibitisha kwa macho yako mwenyewe hulinda maisha yako." },
  { id:7, topic:"Usitokeze ghafla", emoji:"🛑",
    question:"Kwa nini KAMWE, hata kidogo, usitokeze ghafla mbele ya gari, pikipiki, au mkokoteni unaotembea?",
    choices:["Kwa sababu kasi ya chombo itaongezeka zaidi","Kwa sababu chombo kizito hakiwezi kusimama ghafla papo hapo, hata dereva akikanyaga breki kwa hofu (umbali wa kusimama)","Kwa sababu rangi ya chombo itabadilika","Kwa sababu watu wanaokimbia nyuma watakasirika"],
    answerIndex:1,
    explanation:"Gari, mkokoteni, au pikipiki inayotembea haiwezi kusimama papo hapo katika dakika ileile dereva anapokanyaga breki, hata ajitahidi kiasi gani. Kwa sababu ya kasi ya uzito na mwendo wake (hali ya kuendelea kwa mwendo), bila shaka huendelea mbele mita kadhaa tangu breki ianze kufanya kazi hadi isimame kweli. Kwa hiyo, ukitokeza mbele ya chombo kabisa, kitakugonga hata dereva ajitahidi kiasi gani, na kusababisha ajali mbaya yenye majeraha makubwa au kupoteza maisha. Usisahau kamwe kanuni ya kisayansi kwamba chombo hakiwezi kusimama ghafla." },
  { id:8, topic:"Maji na joto kali", emoji:"💧",
    question:"Siku ya joto, unapocheza nje, kwa nini unapaswa kunywa maji hata kabla ya kuhisi kiu?",
    choices:["Kwa sababu kunywa maji baada ya kuhisi kiu husababisha tumbo kuuma","Kwa sababu ubongo unapohisi kiu, maji ndani ya mwili wako tayari yamepungua sana: ni ishara kwamba unaanza kupatwa na joto kali","Kwa sababu usiponywa haraka, maji yataharibika","Kwa sababu kunywa maji mengi hufanya kivuli kiwe baridi zaidi"],
    answerIndex:1,
    explanation:"Kunapokuwa na joto, mwili wako hutoa jasho ili kushusha joto lake. Wakati huo, maji na chumvi hupotea kutoka ndani ya mwili wako kidogo kidogo. La kushangaza, hata maji ya mwilini yakipungua hadi kiwango cha hatari, huchukua muda kidogo kabla ubongo kuhisi kiu. Yaani, unapohisi kiu, mwili wako tayari umetuma ishara ya dharura. Ukiacha hivyo, unapata joto kali: kichwa huuma, unahisi kizunguzungu, na waweza kuzimia. Siku ya joto, hekima ya kuulinda mwili wako salama ni kuweka nyakati maalum na kunywa maji kidogo hata usipohisi kiu." },
  { id:9, topic:"Skrini na macho", emoji:"📱",
    question:"Ukiangalia simu au skrini kwa karibu, au mahali penye giza, kwa muda mrefu, ni madhara gani huleta kwa mwili wako?",
    choices:["Macho yako huwa na nguvu ghafla na kuona mbali hata gizani","Misuli ya macho yako hubaki imekaza na kuchoka, hivyo uwezo wako wa kuona hupungua, unapata maumivu ya kichwa, na hushindwi kulala usiku","Masikio yako husikia kwa shida zaidi","Hakuna kinachobadilika"],
    answerIndex:1,
    explanation:"Mtu anapoangalia kitu cha karibu, hukaza misuli midogo ndani ya jicho ili kukolezea. Ukiendelea kuangalia skrini yenye mwanga mkali kwa karibu mahali penye giza, misuli hii hufanya kazi bila kupumzika, na mwishowe huwa kama ina maumivu makali ya misuli. Hili likiendelea, husababisha mandhari na herufi za mbali kuonekana ukungu. Pia, mwanga mkali utokao skrinini hudanganya ubongo udhani “sasa ni mchana!”, hivyo unapata shida kulala usiku na afya yako huharibika. Unapoangalia skrini, weka mwanga karibu nawe, na mara kwa mara angalia kitu cha mbali ili kupumzisha macho." },
  { id:10, topic:"Kuzuia meno kuoza", emoji:"🦷",
    question:"Ukila peremende na vyakula vitamu mchana kutwa bila kuweka nyakati maalum, kwa nini meno yako huoza kwa urahisi zaidi?",
    choices:["Kwa sababu kula vitu vitamu hubadilisha meno yako kuwa chokoleti laini","Kwa sababu maadamu kuna sukari mdomoni mwako, vijidudu vya kuoza meno huendelea kutengeneza “asidi” muda wote, hivyo muda wa meno kuyeyuka huwa mrefu","Kwa sababu meno yako hushtuka na kung'oka","Kwa sababu kula peremende nyingi huchosha taya yako"],
    answerIndex:1,
    explanation:"Unapokula chakula au peremende, vijidudu vya kuoza meno mdomoni mwako hula sukari ya mabaki ya chakula na kutengeneza “asidi”. Kwa sababu ya asidi hii, kwa kweli meno ya kila mtu huyeyuka kidogo baada ya kula. Lakini baada ya muda, nguvu ya “mate” mdomoni mwako hurekebisha meno yaliyoyeyuka na kuyarudisha safi kama mwanzo. Ukiendelea kula peremende muda wote bila kuweka nyakati maalum, mdomo wako hubaki umejaa asidi na uchafu, na mate hayapati muda wa kurekebisha meno yako. Matokeo yake, mashimo hutokea kwenye meno yako na huoza. Hekima ni kula peremende kwa nyakati maalum na kusukutua mdomo baada ya kumaliza." },
  { id:11, topic:"Jasho na baridi", emoji:"💦",
    question:"Unapocheza kwa nguvu nje na kutoa jasho jingi, hutokea nini ukiendelea kuvaa nguo zilizolowa?",
    choices:["Jasho linapokauka huchukua joto la mwili wako ghafla, hivyo mwili hupoa, hupatwa na mafua kwa urahisi zaidi, na ngozi huwasha","Nguo zako huwa imara zaidi","Mwili wako huzidi kuwa na joto","Hakuna kinachobadilika"],
    answerIndex:0,
    explanation:"Jasho ni maji yanayotoka mwilini mwako ili “kushusha” joto lililopanda zaidi ya kiasi. Kutokana na jasho kubeba joto la ngozi yako linapofukizika hewani, tunaepuka joto kali. Lakini ukiendelea kuvaa nguo zilizolowa hata baada ya kuacha kucheza, joto la mwili wako huendelea kuchukuliwa muda mrefu baada ya jasho kukauka, na safari hii mwili wako hupoa kupita kiasi: kinga yako (nguvu ya kupambana na maradhi) hupungua na hupata mafua. Pia, uchafu wa jasho ukibaki kwenye ngozi, ngozi huparuza na kuwasha. Ukitoa jasho jingi, ni muhimu kujifuta vizuri na kubadilisha nguo." },
  { id:12, topic:"Sumu ya asili", emoji:"🍄",
    question:"Msituni au kando ya njia, umekuta “uyoga” au “tunda la mmea” lenye rangi nzuri sana. Unapaswa kufanya nini?",
    choices:["Kwa kuwa linaonekana tamu, unaling'ata kidogo ili kuonja","Usiweke kamwe mdomoni. Mimea usiyoijua yaweza kuwa na sumu kali inayohatarisha maisha yako","Unalichukua nyumbani na kulitumia kama kiungo cha supu","Unaliweka mfukoni kama hirizi"],
    answerIndex:1,
    explanation:"Miongoni mwa mimea na uyoga wa asili, mingi — ijapokuwa yaonekana mizuri na tamu kiasi gani — ina viambato vyenye sumu kali sana kwa mwili wa binadamu. Zamani sana, watu walijifunza kutokana na makosa mengi ni ipi salama na ipi hatari, na wakapitisha hilo kama maarifa. Mmea ambao bado hujui kama ni salama kwa 100% kamwe usiuweke mdomoni. Kula kidogo tu kwaweza kusababisha kutapika kwa nguvu na tumbo kuuma, na katika hali mbaya zaidi kukugharimu maisha. Kupenda asili ni muhimu, lakini kwa kile ambacho huna maarifa sahihi kukihusu, shika tahadhari ya busara: “usiguse, usile”." },
  { id:13, topic:"Jua na miale ya urujuanimno", emoji:"☀️",
    question:"Ukiendelea kuangaziwa na jua kali la kiangazi (miale ya urujuanimno) bila kufanya lolote, hutokea nini kwa ngozi yako?",
    choices:["Ngozi yako huwa ngumu kama chuma na haiwezi kuumia tena","Kwa nguvu kubwa ya jua, ngozi yako huwa katika hali kama ya kuungua: hugeuka nyekundu, huvimba na kuuma, na kizuizi cha ngozi huvunjika","Ngozi yako huwa nyeupe na yenye kung'aa","Huachi kuhisi njaa"],
    answerIndex:1,
    explanation:"Mwanga wa jua una manufaa pia, kama kusaidia kutengeneza vitamini ndani ya mwili wetu, lakini wakati huohuo una mwanga mkali uitwao “miale ya urujuanimno” unaoharibu chembechembe za ngozi yako. Ukiendelea kuangaziwa na jua kali la kiangazi ukiwa na ngozi wazi, ngozi yako huvimba na kuwa nyekundu, na kuwa kuungua kunakowaka na kuuma sana hata ushindwe kuoga. Huu ni ushahidi kwamba kizuizi cha ngozi yako kimevunjika na kinalia. Unapofanya shughuli nje, linda ngozi yako ya thamani dhidi ya shambulizi la jua kwa kuvaa kofia na kuchagua kivuli kadiri uwezavyo." },
  { id:14, topic:"Mkao sahihi", emoji:"🪑",
    question:"Ukibaki umepinda mgongo kwa “mkao mbaya” muda mrefu, ni jambo gani baya humpata mwili wako?",
    choices:["Mgongo ukipinda, damu nyingi hufika kichwani na huwa na akili zaidi","Mapafu yako hubanwa na kupumua kunakuwa kwa juujuu, hivyo hewa ya oksijeni haifiki ubongoni na umakini hupungua, na uti wa mgongo na kiuno hupinda na kuuma","Miguu yako huzidi kuwa mirefu","Tumbo lako huharibika kwa urahisi zaidi"],
    answerIndex:1,
    explanation:"Ukibaki na mkao ulioinama na mgongo uliopinda, “mapafu” yaliyo ndani ya kifua chako hubanwa. Kisha kiasi cha hewa unachoweza kuvuta kwa mara moja hupungua na kupumua kwako kunakuwa kwa juujuu. Kwa kuwa binadamu huvuta “oksijeni” ya hewani ili kuendesha ubongo na mwili, oksijeni inapopungua huja usingizi haraka, umakini hupungua, na unakuwa mkali. Pia, mzigo wa kupita kiasi huwekwa kwenye uti wa mgongo na kiuno vinavyobeba mwili wako, na mwili huanza kuuma. Kunyoosha nyonga na kuketi mgongo wima ni mkao wa msingi wa kuendesha ubongo wako kwa nguvu kamili." },
  { id:15, topic:"Kanuni za dawa", emoji:"💊",
    question:"Unapomeza “dawa” unayopewa na mtu mzima nyumbani, ni ahadi gani muhimu unayopaswa kuishika bila kukosa?",
    choices:["Ikionekana si tamu, unaamua mwenyewe kuacha kuimeza","Daima meza kipimo sahihi kilichopangwa kwa wakati uliopangwa. Si peremende, kwa hiyo kumeza kupita kiasi huwa sumu kwa mwili wako","Dawa ya rafiki ikionekana inafaa, unamwomba kidogo na kuimeza","Unaimeza yote kwa mara moja kwa juisi badala ya maji"],
    answerIndex:1,
    explanation:"Dawa ni “dutu maalum yenye nguvu kubwa” inayoshinda vijidudu vya maradhi ndani ya mwili wako au kurudisha mwili wako katika hali nzuri. Lakini ukimeza kipimo maradufu kwa mara moja kwa sababu unataka kupona haraka, au ukila kingi kana kwamba ni peremende, nguvu hiyo kubwa badala yake hugeuka kuwa sumu kali inayoshambulia mwili na viungo vyako mwenyewe. Pia, kumeza dawa ya mtu mwingine, iliyotengenezwa kulingana na mwili wa mtu mwingine, ni marufuku kabisa, kwa sababu haifai mwili wako na husababisha ajali kubwa. Dawa ni ngao unayopaswa kuitumia daima ipasavyo, pamoja na mtu mzima, ukifuata kipimo na kanuni zilizoandikwa kwenye maelekezo." },
  { id:16, topic:"Usalama wa vyenye makali", emoji:"✂️",
    question:"Unapotumia “mkasi au kisu (chenye makali)” kwa kazi za mikono au kazi, ni njia ipi sahihi ya kukishika na kukitumia ili usiumie?",
    choices:["Unaweka mkono wako mwingine karibu kabisa na pale makali yanapoelekea, na kukata","Kamwe huweki mkono wako wala vidole vyako katika upande makali yanapoelekea, na huelekezi makali kwa watu","Unakizungusha kwa nguvu zako zote ili kikate vizuri","Unakibeba mfukoni makali yakiwa wazi"],
    answerIndex:1,
    explanation:"Vyenye makali kama mkasi na visu vidogo ni vifaa vizuri vinavyokata vitu kwa urahisi, lakini kosa moja tu na huwa silaha hatari zinazokata ngozi na nyama yako mwenyewe kwa kina. Unapotumia chenye makali, weka mkono mwingine unaoshikilia kitu mahali “salama ambapo, hata mkono wako ukiteleza na makali yakiruka upande huo, hayatauafikia kabisa”. Ukiweza kutabiri nafasi na usiweke mwili wako au wa mtu mwingine katika njia ya kifaa, hutaumia vibaya hata mkono ukiteleza. Tawala vizuri nguvu ya kifaa na ukitumie kwa usalama." },
  { id:17, topic:"Mshtuko wa umeme", emoji:"⚡",
    question:"Hutokea nini ukiingiza waya wa chuma au pini ndani ya tundu la soketi ya umeme nyumbani au katika jengo?",
    choices:["Maji safi hububujika kutoka kwenye soketi","Umeme wenye nguvu sana unaopita ndani ya ukuta huingia mwilini mwako kwa papo hapo na kusababisha kuungua vibaya au kusimamisha moyo wako (mshtuko wa umeme)","Umeme wote wa nyumba yako huzimika tu, na ndiyo mwisho","Hakuna kinachotokea"],
    answerIndex:1,
    explanation:"Ndani kabisa ya matundu ya soketi kwenye kuta za jengo hupita, saa 24 kwa siku, umeme wenye nguvu sana na hatari ili kuendesha televisheni na mashine za nyumba nzima. Umeme una tabia ya kupita kwa urahisi sana kupitia chuma, kama feleji na waya. Ukiingiza waya au uma ndani ya tundu la soketi, umeme wa ndani ya ukuta husafiri kupitia chuma hicho na kufurika mwilini mwako papo hapo. Hii huitwa “mshtuko wa umeme”. Umeme wenye nguvu huleta madhara makubwa kwa mwili na moyo wa binadamu, na waweza kukunyang'anya maisha. Kamwe usiweke kitu chochote ndani ya tundu la soketi." },
  { id:18, topic:"Maeneo hatari", emoji:"🕳️",
    question:"Kwa nini hupaswi kukaribia “maeneo hatari” yasiyo na watu wazima, kama kisima kirefu, genge linaloporomoka, au magofu ya jengo la zamani?",
    choices:["Kwa sababu nguo zako zitachafuka huko","Kwa sababu ukibahatika kuanguka shimoni au kufukiwa na maporomoko, hakuna anayeweza kutambua na hutaweza kuomba msaada","Kwa sababu kuna hazina iliyofichwa huko","Kwa sababu mizimu hutoka huko"],
    answerIndex:1,
    explanation:"Duniani kuna maeneo hatari mengi yanayoonekana kama viwanja vya kuchezea vya kufurahisha kwa mtazamo wa kwanza, lakini kwa hatua moja ya kukosea yaweza kukugharimu maisha. Karibu na kisima kirefu, juu ya genge linaloporomoka, au kwenye magofu ya zamani, ardhi chini ya miguu yako yaweza kuporomoka ghafla. Jambo la kutisha zaidi ni kwamba ajali ikitokea mahali pasipo na mtu mzima yeyote karibu, hakuna atakayetambua kuwa umenaswa pale, na hutaweza kuokolewa huku maji na chakula chako vikiisha. “Hekima ya kutabiri hatari” — kutokaribia maeneo hatari tangu mwanzo — ndiyo inayolinda maisha yako kwa uhakika zaidi." },
  { id:19, topic:"Ishara za homa", emoji:"🤒",
    question:"“Mwili kutetemeka na kuhisi baridi (kutetemeka kwa baridi)” ni ishara ya nini kinachokaribia kutokea ndani ya mwili wako?",
    choices:["Ishara kwamba joto la chumba limeshuka ghafla","Kwa kuwa vijidudu vimeingia mwilini mwako, ni ishara kwamba ubongo unakaribia kupandisha joto la mwili wako kwa kasi (kuleta homa) na kuanza vita ili kuvichoma vijidudu","Ishara kwamba mwili wako unageuka kuwa barafu","Ishara kwamba chakula chako kimemaliza kumeng'enywa"],
    answerIndex:1,
    explanation:"Wakati pande zote zikiwa na joto na bado wewe peke yako unahisi baridi ya kutetemeka, huo ni ushahidi kwamba vijidudu au virusi, kama vya mafua, vimevamia mwili wako. Timu ya ulinzi (kinga) ya mwili wako hujaribu kupandisha joto lako kwa makusudi hadi juu sana, ili kushinda vijidudu vilivyo dhaifu mbele ya joto. Katika hatua hii ya maandalizi ya “sasa nitapandisha joto na kupigana!”, ubongo hudhani kimakosa kwamba pande zote zina baridi na hujaribu kutengeneza joto kwa kuutetemesha mwili wako, ndiyo maana unahisi baridi. Ishara hii inapotokea, hekima sahihi ni kuvaa nguo za joto mara moja, kulala chini, kupumzisha mwili wako, na kuunga mkono vita vya timu yako ya ulinzi." },
  { id:20, topic:"Hatari ya kucheza kwa ukali", emoji:"🤕",
    question:"Unapocheza na rafiki zako, kwa nini ni vibaya kuwasukuma kwa nguvu kutoka nyuma kwa mzaha au kuwapiga chenga ya mguu?",
    choices:["Kwa sababu nguo za rafiki yako zitachafuka","Kwa sababu mtu aliyeshtukizwa (asiyejiandaa) hawezi kunyoosha mikono kujikinga, na anaweza kugonga kichwa chake kwa nguvu ardhini na kupata jeraha linalohatarisha maisha yake","Kwa sababu kusukuma hupunguza uzito wako mwenyewe","Kwa sababu mtu atakukemea na kukufanya usimame ukumbini"],
    answerIndex:1,
    explanation:"Mtu, akijua “huenda nitaanguka sasa”, anaweza kunyoosha mikono bila kufikiri ili kukinga uso na kichwa chake. Lakini akisukumwa ghafla kutoka nyuma au kupigwa chenga bila tahadhari, ubongo haupati muda wa kujiandaa kumkinga, hivyo mikono haitoki na anagonga uso au kichwa moja kwa moja kwenye jiwe au pembe ngumu ya ardhi. Fuvu la kichwa likivunjika au ubongo ukijeruhiwa vibaya, huwa ajali mbaya inayoweza kumwacha bila kuweza kutembea maisha yote, au kumgharimu maisha. Ulichofikiri ni “mzaha mdogo tu” chaweza kunyang'anya maisha ya rafiki mpendwa. Daima tenda kwa kuwaza usiwafanyie wengine kamwe kile ambacho kingekuwa hatari kweli kama kingefanywa kwako." },
  { id:21, topic:"Nguvu ya sumaku", emoji:"🧲",
    question:"Unapokaribisha sumaku mbili pamoja na kujaribu kuunganisha alama zinazofanana (N na N, au S na S), hutokea nini?",
    choices:["Zinashikamana kwa nguvu","Kwa nguvu isiyoonekana, zinasukumana kwa nguvu na kujaribu kuachana (zinakingana)","Sumaku zinageuka ghafla kuwa mchanga","Hakuna kinachotokea"],
    answerIndex:1,
    explanation:"Sumaku ina nyuso mbili tofauti, ziitwazo “ncha N” na “ncha S”. Unapokaribisha nyuso tofauti (N na S), zinashikamana kwa nguvu na kwa urafiki. Lakini unapojaribu kuunganisha nyuso zinazofanana (N na N, au S na S), nguvu isiyoonekana na yenye nguvu sana inazisukuma ziachane, kana kwamba inasema “ondoka!”. Nguvu hii isiyoonekana na ya ajabu huitwa “usumaku”. Katika viwanda, mashine, na hata ndani ya simu ulimwenguni kote, nguvu hii ya kusukuma na nguvu hii ya kuvuta hutumika kwa ustadi kujenga teknolojia nyingi zinazohamisha vitu na kuzisimamisha." },
  { id:22, topic:"Umeme tuli", emoji:"💥",
    question:"Siku kavu, ukisugua kwa nguvu kitambaa kikavu au fimbo ya plastiki na kitu kingine, hutokea umeme wa ajabu unaovuta vitu. Ni nini?",
    choices:["Umeme wa radi wa kwenye soketi","“Umeme tuli”, unaopiga kelele za kupasuka na kutoa cheche na kuvuta takataka nyepesi na nywele","Umeme unaopoza maji","Hakuna kinachotokea"],
    answerIndex:1,
    explanation:"Unaposugua vitu viwili kwa nguvu, chembe ndogo za umeme zilizokuwa zimejificha ndani hukusanyika kwa wingi juu ya uso na kuanza kuvurugika. Hii huitwa “umeme tuli”. Umeme tuli una nguvu ya ajabu ya kuvuta vitu vyepesi vilivyo karibu — nywele, vumbi, karatasi nyembamba — kwa “fwaa”, kama vile sumaku. Mahali penye giza, nyakati nyingine zaweza kuonekana cheche ndogo za buluu zikipasuka. Hata kifaa kikavu kinachoonekana hakifanyi lolote chaweza kuzalisha umeme kupitia msuguano: ni mfumo wa kuvutia wa asili." },
  { id:23, topic:"Vivuli na jua", emoji:"🌇",
    question:"Unaposimama nje, kivuli unachotupa ardhini huwa kirefu zaidi jua likiwa katika nafasi ipi?",
    choices:["Jua likiwa juu ya kichwa chako kabisa, katika sehemu ya juu zaidi","Asubuhi au jioni, jua likiwa chini, karibu na ardhi","Jua likiwa limejificha nyuma ya wingu","Urefu daima ni uleule"],
    answerIndex:1,
    explanation:"Urefu wa kivuli hubadilika kila siku kwa kanuni maalum, kulingana na “kimo” cha jua. Asubuhi na jioni, jua likiwa chini na karibu na ardhi, mwanga huingia ubavuni kwa pembe ndefu iliyoinama, hivyo kivuli ardhini hunyooka kwa urefu wa kushangaza. Kinyume chake, karibu na adhuhuri, jua linapofika juu ya kichwa chako kabisa katika sehemu ya juu zaidi, mwanga huanguka moja kwa moja chini, hivyo kivuli hupungua kuwa kidogo miguuni mwako na huwa kifupi zaidi. Hata bila saa au umeme, kwa kuchunguza kwa makini “mwelekeo na urefu wa vivuli”, waweza kukadiria kwa usahihi takriban ni saa ngapi sasa na muda kiasi gani umebaki hadi usiku kuingia." },
  { id:24, topic:"Jinsi joto linavyosafiri", emoji:"🥄",
    question:"Umeingiza kijiko cha chuma na kijiko cha mbao ndani ya sufuria ya supu iliyo motoni. Ni kipi kinachoshika joto la hatari haraka zaidi ukikigusa?",
    choices:["Kijiko cha mbao","Kijiko cha chuma (feleji au alumini)","Hakuna kinachopata joto hata kidogo","Vyote vinapata joto sawa kwa wakati mmoja"],
    answerIndex:1,
    explanation:"Miongoni mwa vitu duniani, baadhi ni “bora sana katika kupitisha joto” na baadhi ni “dhaifu katika kulipitisha”. Vyuma kama feleji na alumini vina tabia ya kuhamisha joto ndani yake kwa kasi kubwa (upitishaji joto), hivyo joto husafiri kutoka chini ya sufuria inayogusa moto hadi sehemu ya juu unayoishika, na huwa moto sana papo hapo. Ukikigusa bila tahadhari, unaungua vibaya. Kinyume chake, mbao, kitambaa, na plastiki hupitisha joto vibaya, hivyo havipati joto haraka hata vikiwa karibu na moto. Unapotumia moto kupika kwa usalama, unahitaji hekima ya kujua tabia hii ya vitu na kuweka mbao au kitambaa pale unaposhika." },
  { id:25, topic:"Sauti ni nini", emoji:"🥁",
    question:"Ni nini hasa asili ya “sauti” zote — sauti yako mwenyewe, sauti ya ngoma, mbweko wa mbwa, na kadhalika?",
    choices:["Bonge la hewa lililoganda likikurukia","Nguvu ya vitu vinapotetemeka kwa wororo, inayofika masikioni mwako ikiwa imegeuka mawimbi hewani","Sauti ya mdudu asiyeonekana","Mwanga uliogeuka kuwa sauti"],
    answerIndex:1,
    explanation:"Asili hasa ya kila sauti ni “mtetemeko (mtikisiko)”. Unapopiga ngoma, ngozi yake hutetemeka kwa wororo, na unapoweka mkono kooni na kuzungumza, unahisi ndani ya koo lako linatetemeka. Mtetemeko huu wa vitu hutetemesha “hewa” iliyopo kandokando moja baada ya nyingine, na husonga ukiwa umegeuka wimbi (wimbi la sauti), hutetemesha utando ulio ndani ya masikio yetu, na hivyo ubongo huinasa kama “sauti”. Katika utupu wa anga, ambapo hakuna hewa kabisa, hata upige kelele kiasi gani au upige ngoma, hakuna kinachopitisha mtetemeko, hivyo kuna ukimya kamili. Kujua kwamba sauti ni mtetemeko ni msingi wa mawasiliano yote na muziki wote." },
  { id:26, topic:"Mng'ao wa nuru", emoji:"🔦",
    question:"Unapoelekeza mwanga wa jua kwenye “kioo” au uso wa maji tulivu, hutokea nini kwa mwanga?",
    choices:["Mwanga hufyonzwa na kioo na kutoweka","Hurudi nyuma moja kwa moja, kwa pembe ileile uliyofika nayo (huakisi)","Mwanga huongezeka mara mbili ya ung'avu","Rangi ya mwanga huwa nyeusi yote"],
    answerIndex:1,
    explanation:"Mwanga unapogonga kitu laini na bapa, una tabia ya “kurudi nyuma” kwa pembe nadhifu, kama vile mpira unaogonga ukuta. Hii huitwa “mng'ao (uakisi)” wa nuru. Ukijua tabia hii, waweza kutumia kioo au chuma kilichong'arishwa kurudisha mwanga wa jua na kuangaza ndani ya pango lenye giza ambalo mwanga haufiki, au kutuma ishara ya mwanga inayong'aa kwa wenzako walio mbali juu ya mlima ili kuwaonya hatari au kuomba msaada." },
  { id:27, topic:"Maji na barafu", emoji:"🧊",
    question:"Ukiacha “maji” ndani ya ndoo mahali penye baridi kali sana, baridi ya kutosha kuyaganda, umbo lake hubadilikaje?",
    choices:["Hugeuka kuwa maji ya moto","Hugeuka kuwa “barafu” ngumu na gumegume, na ujazo wake wote huongezeka kidogo na kuwa mkubwa","Maji hupungua hadi nusu ya kiasi chake","Hakuna kinachobadilika"],
    answerIndex:1,
    explanation:"Maji ni dutu ya ajabu inayobadilisha umbo lake sana kulingana na halijoto: “kiowevu, kigumu, gesi”. Halijoto inaposhuka na yakaganda, hugeuka kuwa “barafu” ngumu. Karibu vitu vyote hupungua vinapopozwa, lakini maji ni ya pekee: yanapokuwa barafu, mpangilio wa ndani yake hubadilika, hivyo huwa na tabia adimu ya kwamba yote “huvimba kidogo na kuwa makubwa (ujazo wake huongezeka)”. Kwa sababu hii, ukiganda chupa ya kioo au bomba la chuma lililojaa maji pomoni bila nafasi, hayawezi kustahimili nguvu ya kuvimba kutoka ndani, na chupa au bomba hupasuka kwa mlio na kuvunjika. Ili kutunza vifaa katika maeneo ya baridi, hekima ya kujua mabadiliko haya ya maji ni ya lazima." },
  { id:28, topic:"Jinsi vitu vinavyoyeyuka", emoji:"🧂",
    question:"Umeweka “chumvi” au “sukari” ndani ya maji na kuchanganya vizuri, na umbo lake limetoweka machoni. Chumvi katika maji haya imekuwaje?",
    choices:["Imetoweka kabisa na haipo tena","Imevunjika kuwa chembe ndogo zisizoweza kuonekana na “imeyeyuka kwa usawa (bado ipo)” katika maji yote","Imegandamana chini ya ndoo, imejificha","Maji yameila chumvi yote"],
    answerIndex:1,
    explanation:"Chumvi au sukari kuchanganyikana na maji hadi isionekane huitwa “kuyeyuka”. Inakuwa isiyoonekana, lakini chumvi haijatoweka mahali popote. Imegawanyika tu kuwa vipande vidogo sana sana na imechanganyika kwa usawa katika maji yote. Ushahidi ni kwamba maji hayo yana ladha ya chumvi, na ukiyaweka maji motoni na kuyafukiza yote, chini hubaki chumvi ileile ya awali kwa uzito uleule kabisa. Hata mtu katika jamii akijaribu kukudanganya kwa kusema “haipo pale kwa sababu huioni”, kwa jicho hili la kisayansi waweza kuona asili halisi ya vitu na usidanganyike." },
  { id:29, topic:"Upepo ni nini", emoji:"🌬️",
    question:"“Upepo” unaovuma nje, kwa hakika ni nini kinachosonga?",
    choices:["Pumzi ya kiumbe kikubwa kisichoonekana","Mtiririko wa “hewa” inayozunguka Dunia, inayohama inapopata joto na kupoa","Kivuli kinachotupwa na mwanga wa jua unaokimbia","Nguvu ya mawingu yanayosukuma ardhi"],
    answerIndex:1,
    explanation:"Asili hasa ya upepo ni “mtiririko wa hewa” iliyo kandokando yetu. Hewa ya Dunia, ikipata joto kutoka kwa jua, huwa nyepesi na hupanda juu, na hewa ya baridi huwa nzito na hushuka chini. Kwa sababu ya tofauti hii ya halijoto ya hewa, hewa yote ya Dunia husonga kwa nguvu ikizunguka, na hivyo upepo huzaliwa. Upepo hauonekani, lakini ukinaswa kwenye tanga waweza kusukuma meli kubwa, na kwa kuzungusha mabawa ya kinu cha upepo waweza kusaga ngano nzito kuwa unga au kuzalisha umeme: ni “nishati ya mwendo” kubwa ya asili kuu." },
  { id:30, topic:"Mvuto wa nchi", emoji:"🌍",
    question:"Unapoachia hewani jiwe unaloshikilia mkononi, jiwe daima huanguka kuelekea “ardhi (chini)”. Kwa nini?",
    choices:["Kwa sababu jiwe linataka kupumzika ardhini","Kwa sababu “Dunia” tunayoishi ina nguvu iitwayo “mvuto wa nchi” inayovuta kila kitu kwa nguvu kuelekea kitovu chake","Kwa sababu kutoka juu unavuma upepo mkali unaolisukuma","Kwa sababu jiwe ni zito hivyo husonga lenyewe"],
    answerIndex:1,
    explanation:"Kila kitu duniani, ukikiachia, daima huanguka chini (kuelekea ardhi). Hii ni kwa sababu nyota kubwa tunayosimama juu yake — Dunia yenyewe — ina nguvu kama ya sumaku inayovuta vitu vyote kwa imara kuelekea kitovu chake. Nguvu hii huitwa “mvuto wa nchi”, au “mvutano wa ulimwengu”. Kutokana na mvuto huu, hata Dunia izunguke kwa kasi kiasi gani angani, sisi binadamu, maji ya bahari, na majengo hatutupwi angani, na twaweza kuishi kwa usalama miguu yetu ikiwa imara ardhini." },
  { id:31, topic:"Nguvu ya msuguano", emoji:"👟",
    question:"Kwa nini kwenye njia ya matope au juu ya barafu huteleza na kuanguka kwa urahisi, lakini juu ya mwamba mkwaruzo ni vigumu kuteleza?",
    choices:["Kwa sababu mwamba ni mpole zaidi","Kwa sababu “nguvu ya msuguano” inayozuia vitu vinaposuguana ni kubwa zaidi kwenye uso mkwaruzo","Kwa sababu barafu ni nyepesi hivyo huwarusha watu","Kwa sababu viatu huogopa barafu"],
    answerIndex:1,
    explanation:"Vitu vinapogusana na kusonga kimoja juu ya kingine, daima kuna nguvu ya kuzuia iitwayo “msuguano” inayojaribu kusimamisha mwendo. Juu ya barafu laini au matope mabichi, breki hii ya msuguano karibu haifanyi kazi, hivyo miguu yako huteleza na kuanguka vibaya, na kuvunjika mfupa au kuumia kwa urahisi. Kinyume chake, kwenye ardhi mkwaruzo, au kwenye mistari mirefu ya chini ya kiatu, msuguano ni mkubwa na hushika ardhi kwa imara, hivyo waweza kutembea bila kuteleza. Unapotembea katika maeneo hatari, hekima ya usalama wako ni kuzingatia kiasi gani chini ya viatu vyako vimechakaa na msuguano wa ardhi." },
  { id:32, topic:"Nguvu ya kuelea", emoji:"🛶",
    question:"Ukitupa “gogo la mti” kubwa sana na zito kwenye mto au bahari, je, huzama? Au huelea?",
    choices:["Kwa kuwa ni zito, huzama hadi chini papo hapo","Ingawa gogo ni kubwa sana, ni jepesi kuliko maji ya ukubwa uleule, kwa hiyo “huelea juu ya maji”","Huvunjika vipande vipande mara linapogusa maji","Kuzama au kuelea hubadilika kulingana na siku"],
    answerIndex:1,
    explanation:"Kitu kuelea au kuzama majini hakuamuliwi tu na uzito wake wote. Huamuliwa na “kama ni kizito au kijepesi (msongamano wake) ukilinganisha na maji ya ukubwa (ujazo) uleule”. Mbao ina mifuko mingi ya hewa isiyoonekana ndani yake, kwa hiyo hata gogo liwe kubwa na zito kiasi gani, ni jepesi kuliko bonge la maji la ukubwa uleule. Ndiyo maana hupokea nguvu inayolisukuma juu kutoka majini (nguvu ya kuelea) na huelea juu. Ni kwa sababu watu walijua kanuni hii ya asili ndipo binadamu aliweza kujenga meli kutoka vipande vikubwa vya mbao na kuvumbua teknolojia ya kuvuka bahari akibeba mizigo mizito mingi." },
  { id:33, topic:"Nuru husafiri moja kwa moja", emoji:"💡",
    question:"Mwanga wa jua au wa tochi husafirije katika hewa?",
    choices:["Husafiri ukipinda huku na huko, kama upepo","Husafiri “moja kwa moja kabisa (mstari ulionyooka)”, na kitu kinapokuwa njiani huzuiwa na kutengeneza kivuli nyuma","Husafiri ukichora miduara mara kwa mara","Mwelekeo wake hauamuliwi kabisa"],
    answerIndex:1,
    explanation:"Nuru ina kanuni isiyobadilika: katika hewa husafiri “moja kwa moja kabisa, mbali kadiri iendavyo”. Hii huitwa “usafiri wa mstari ulionyooka” wa nuru. Kwa kuwa nuru haiwezi kupinda, kitu “kisichopitisha nuru” — mwili wa mtu, mwamba mkubwa — kinaposimama katika njia yake iliyonyooka, nuru haiwezi kuzunguka hadi nyuma ya kitu hicho, na eneo lenye giza ambalo nuru haifiki hubaki ardhini. Hii ndiyo asili halisi ya “kivuli”. Kwa kutumia tabia ya nuru kusafiri moja kwa moja, watu hujenga majengo yaliyonyooka kabisa na kupima umbali wa mbali kwa usahihi." },
  { id:34, topic:"Hewa yenye joto", emoji:"🔥",
    question:"Unapowasha moto wa kambi, kwa nini “moshi” na hewa ya joto vinavyotoka daima hupanda juu (kuelekea angani)?",
    choices:["Kwa sababu moshi unataka kukutana na mawingu angani","Kwa sababu hewa “huwa nyepesi inapopashwa joto” na ina tabia ya kupanda juu zaidi na zaidi, juu ya hewa ya baridi iliyo kandokando","Kwa sababu kutoka juu kuna uzi usioonekana unaovuta","Kwa sababu moto huurusha moshi juu"],
    answerIndex:1,
    explanation:"Hewa ina kanuni ya kuvutia: uzito wake hubadilika kulingana na halijoto. Hewa “iliyopashwa joto” hadi kuwa nyekundu na joto la moto huwa changamfu na huvimba sana, ikawa “nyepesi kwa uzito” kuliko hewa ya baridi iliyo kandokando. Ndiyo maana, kama puto inayoelea majini, hupanda juu zaidi na zaidi yenyewe. Moshi wa moto wa kambi daima hupanda juu kwa sababu umepanda juu ya mtiririko huu wa hewa ya joto. Kujua mwendo huu wa hewa — “hewa ya joto hupanda juu, ya baridi hushuka chini” (mzunguko wa joto) — huwa hekima muhimu ya kupitisha hewa chumbani, na ya kuepuka moshi na kutoroka kwa usalama wakati wa moto." },
  { id:35, topic:"Kurudi kwenye umbo", emoji:"🏹",
    question:"Baada ya kuvuta au kukunja kwa nguvu kwa mkono mpira wa raba au tawi linaloweza kupinda, hutokea nini ukiachia?",
    choices:["Hubaki katika umbo lililokunjwa na halirudi kamwe katika umbo la awali","Hufanya kazi kwa nguvu “nguvu inayojaribu kurudi katika umbo la awali (unyumbufu)”","Uzito wa kitu huongezeka maradufu","Hutoa joto na kuanza kuwaka"],
    answerIndex:1,
    explanation:"Raba na matawi machanga ya miti yana nguvu kali inayojaribu “kurudi katika umbo lake la awali papo hapo” unapoachia, hata baada ya nguvu ya nje kubadilisha umbo lake. Nguvu hii huitwa “unyumbufu” katika lugha ya sayansi. Tangu zamani sana, binadamu ametumia kwa ustadi nguvu hii kali inayojaribu kurudi katika umbo la awali: kutengeneza vifaa vinavyorusha vitu mbali (kama upinde na mshale), kutengeneza mitego, na kufunga mizigo kwa imara kwa kamba imara. Kujua nguvu ya kurudi nyuma ya vitu vilivyo kandokando yako huwa hekima ya kutumia vifaa kwa usalama." },
  { id:36, topic:"Uvukizaji", emoji:"🌫️",
    question:"“Kidimbwi cha maji” kilichotengenezwa ardhini baada ya mvua kilitoweka kabisa siku iliyofuata kulipokuwa na jua. Maji yalikwenda wapi?",
    choices:["Watu wa chini ya ardhi, ndani ya udongo, waliyanywa yote","Kwa joto la jua na sababu nyingine, yaligeuka kuwa chembe ndogo zisizoonekana (mvuke wa maji) na “yakajificha hewani” (yalivukiza)","Maji yaliogopa na kukimbilia mahali fulani","Jua liliyafyonza maji na kuyala"],
    answerIndex:1,
    explanation:"Maji ya kidimbwi hutoweka kwa sababu maji hugeuka kuwa chembe ndogo zisizoonekana (mvuke wa maji katika hali ya gesi), huchanganyika na hewa, na kuruka mbali. Hii huitwa “uvukizaji” wa maji. Nguo zilizolowa zilizoanikwa nje kukauka vizuri pia ni kutokana na mfumo huu wa uvukizaji. Maji, hata yasipoonekana tena, daima yapo hewani, na yanapokusanyika juu angani na kupozwa, hugeuka tena kuwa “mawingu” na “mvua” na huanguka tena ardhini. Maji yote ulimwenguni husafiri hivi yakizunguka Dunia, yakibadilisha umbo (mzunguko wa maji)." },
  { id:37, topic:"Chuma na kutu", emoji:"🔧",
    question:"Ukiacha kisu au kifaa cha chuma cha thamani kikiwa kimelala juu ya matope huku bado kikiwa kimelowa, hutokea nini?",
    choices:["Chuma husuguliwa na kuanza kung'aa","Oksijeni ya hewani na maji huungana na chuma na kukigeuza kuwa “kutu” ya kahawia-nyekundu inayobomoka, na kifaa huharibika","Chuma hukua zaidi na zaidi na kuwa kikubwa na kizito","Hakuna kinachobadilika"],
    answerIndex:1,
    explanation:"Chuma ni madini imara sana na yenye manufaa, lakini ina udhaifu mkubwa. Ukikiacha kikiwa kimelowa, au ukikiweka hewani muda mrefu, hufanya mwitikio wa kemikali na maji na oksijeni na kugeuka kuwa dutu ya kahawia-nyekundu inayobomoka. Hii huitwa “kutu” (kuoza kwa hewa) ya chuma. Chuma kilichoshika kutu hupoteza uimara wake na hubomoka kwa kuguswa tu, na huwa hakifai kama kifaa. Ili kulinda vifaa vya thamani dhidi ya kutu, unahitaji hekima ya utunzaji wa kila siku: baada ya kuvitumia, daima futa maji hadi safi na paka tabaka jembamba la “mafuta” juu ya uso, ili maji na hewa visiguse chuma moja kwa moja." },
  { id:38, topic:"Usanisinuru", emoji:"🌱",
    question:"Hata ukimwagilia kila siku maji ya kutosha mmea wa bustanini au shambani, hutokea nini ukimfungia katika “sanduku lenye giza totoro” lisilofikiwa na mwanga wowote?",
    choices:["Hukua kwa uhuru na kuwa mkubwa kwa sababu jua halimpigi","Bila mwanga hauwezi kujitengenezea chakula (nishati) cha kuishi, hivyo hubadilika njano na kunyauka","Mmea hugeuka kuwa mnyama na kuondoka ukitembea","Hakuna kinachobadilika"],
    answerIndex:1,
    explanation:"Binadamu na wanyama hupata nishati ya kuishi kwa kula chakula kingine kwa mdomo. Lakini mmea, usioweza kuondoka ardhini, lazima ujitengenezee nishati yake kwa nguvu zake mwenyewe. Kwa kuzamisha majani yake ya kijani katika “mwanga wa jua”, mmea una nguvu ya kimuujiza ya kutengeneza, kutoka kwa maji na hewa, chakula bora zaidi (sukari kama wanga) cha kujenga mwili wake mwenyewe. Hii huitwa “usanisinuru”. Hata umwagilie maji kiasi gani, mahali penye giza totoro pasipo na mwanga wa jua, mmea hupata utapiamlo na hunyauka kwa 100%. Huu ni msingi wa kuelewa jinsi mwanga wa jua ulivyo muhimu katika kilimo." },
  { id:39, topic:"Maji hubaki sawa", emoji:"🥛",
    question:"Unapotia maji ndani ya kikombe au sahani, hata uiname chombo kiasi gani, hutokea nini kwa umbo la uso wa maji?",
    choices:["Huganda ukiwa umeinama kwa pembe ileile ya chombo","Hata chombo kiiname kiasi gani, uso wa maji daima huwa “bapa (sawa) na ardhi ya Dunia”","Uso wa maji huchongoka juu kama pembetatu","Huanza kuzunguka ukifuata mwinamo wa chombo"],
    answerIndex:1,
    explanation:"Vimiminika kama maji huvutwa daima moja kwa moja chini na mvuto wa Dunia, kwa hiyo katika chombo chochote uvitiacho na kukiiname, uso wake daima huwa katika “hali bapa kabisa”, sambamba na ardhi. Hii huitwa “usawa” (uliolala sawa). Zamani sana, maseremala na wajenzi walitumia sana tabia hii ya maji. Kwa kujaza maji katika bomba au mfereji wa uwazi, walitengeneza kifaa (kipima usawa) cha kuthibitisha kwa usahihi wa 100% kama sakafu na nguzo za jengo walilokuwa wakijenga zilikuwa “bapa kabisa kulingana na ardhi” au “zimeinama na kupotoka”. Maji ni mwalimu anayetufundisha “usawa” wa ulimwengu." },
  { id:40, topic:"Kubeba mizigo mizito", emoji:"📦",
    question:"Unapobeba kwa mkono mzigo wa kuni au mzigo mzito sana, ni namna ipi ya kuushika inayokuwezesha kuubeba kwa uthabiti na usalama kwa “nguvu nyepesi zaidi”?",
    choices:["Unanyoosha mikono moja kwa moja na mirefu mbele na kuushika mzigo mbali na mwili","Unaushika mzigo umebandika kabisa kwenye tumbo au kifua chako, ukiutegemeza katikati ya mwili wako","Unauweka kwa shida juu ya kichwa na kuushika kwa mkono mmoja","Unaushika mzigo ukining'inia kwenye ncha za vidole tu"],
    answerIndex:1,
    explanation:"Unapobeba kitu kizito, kukishika mbali na mwili hufanya kazi kama nguzo ya kuinulia: uzito wa mzigo huangukia mikono na kiuno chako mara nyingi zaidi, hivyo unaishiwa nguvu haraka au unapoteza usawa na kupinduka. Lakini unapouvuta mzigo umebandika kabisa kwenye “eneo la tumbo au kifua chako (katikati ya mwili wako, kitovu chako cha uzito)” na kuushika karibu, uzito wa mzigo huwa kitu kimoja na uzito wako mwenyewe, hivyo waweza kuubeba kwa mtikisiko mdogo zaidi na kwa nguvu nyepesi cha kushangaza, kwa usalama. Hii ni hekima ya pamoja ya ulimwengu mzima ya jinsi ya kutumia mwili, ili utumie nguvu zako chache kwa uangalifu na ufanye kazi kwa ufanisi bila kuumia." },
  { id:41, topic:"Tetemeko: ndani ya nyumba", emoji:"🏠",
    question:"Ardhi inaanza kutetemeka kwa nguvu (tetemeko la ardhi). Unapokuwa ndani ya jengo, ni jambo gani la kwanza la kufanya?",
    choices:["Kukimbia kwa haraka kuelekea nje kwa hofu","Kutambaa chini ya dawati au meza imara, na kulinda kichwa chako vizuri mahali ambapo samani hazitakuangukia","Kukaribia dirisha na kuangalia kinachoendelea nje","Kukimbia ndani ya chumba huku ukipiga kelele"],
    answerIndex:1,
    explanation:"Tetemeko linapotokea, hatari kubwa zaidi ni 'vitu kuanguka kutoka juu' na 'samani nzito kupinduka na kukugandamiza chini'. Ukijaribu kukimbilia nje kwa hofu, kioo kilichovunjika au vigae vya paa vinaweza kukuangukia kichwani na kukujeruhi vibaya. Unapohisi mtetemeko, kwanza jifiche chini ya kitu imara kinachozuia mgongano kutoka juu, kama dawati au kitanda. Kisha weka kichwa chako kimefunikwa kwa mikono au mto na subiri bila kusonga hadi mtetemeko ukome kabisa: hii ni kanuni ya kwanza ya kulinda maisha, inayoshirikiwa duniani kote." },
  { id:42, topic:"Tetemeko: nje", emoji:"🏞️",
    question:"Tetemeko kubwa (la ardhi) linatokea ukiwa unatembea nje. Ni wapi salama zaidi kukimbilia?",
    choices:["Karibu na jengo refu, ukuta wa zamani wa matofali, au genge","Mahali penye mabango na miti mingi","Mahali wazi, pana na salama ambapo hakuna kitu chochote kinachoweza kukuangukia","Chini ya daraja kubwa lililo karibu"],
    answerIndex:2,
    explanation:"Tetemeko likitokea ukiwa nje, kanuni ya chuma ni 'kujiweka mbali kadiri uwezavyo' na majengo na kuta. Kuta za zamani za matofali au saruji, kioo cha majengo, na magenge, vinaweza kuporomoka mara moja kwa mtetemeko na kuwa silaha hatari zinazoangukia watu. Hamia mahali pana na wazi ambapo hakuna majengo ya kupinduka, hakuna mabango ya kuanguka, na hakuna miteremko ya kuporomoka. Kama hakuna mahali kama hapo karibu, linda kichwa chako kwa imara kwa mkoba au kitu kama hicho, na subiri mtetemeko ukome ukiwa katika njia salama mbali na majengo." },
  { id:43, topic:"Maji ya mafuriko", emoji:"🌧️",
    question:"Mvua kubwa imenyesha na maji yamefurika barabarani. Kama mkondo una kina cha kama 'goti', je, ni sawa kuvuka kwa miguu?",
    choices:["Kina cha goti ni kifupi, kwa hiyo unaweza kuvuka kwa kukimbia kwa urahisi","Usivuke kamwe. Nguvu ya maji yanayotiririka ni kubwa sana, na hata kwa kina cha goti yaweza kumsomba mtu mzima kwa urahisi","Ni salama ukiogelea kuvuka","Unaweza kuvuka kama maji ni safi"],
    answerIndex:1,
    explanation:"Usidharau nguvu ya maji yanayotiririka. Maji yanapofika kimo cha goti, mkondo husukuma kwa nguvu kusomba miguu yako, hivyo hata mtu mzima hawezi kusimama imara: huanguka mara moja na husombwa kama alivyo hadi maji ya kina chini ya mto. Pia, hatuoni kupenya maji ya matope, kwa hiyo duniani kote hutokea ajali mbaya ambapo watu huanguka kwenye mtaro wa kina uliofichwa au tundu la maji taka lililo wazi na kuzama. Mara tu maji yanapoanza kutiririka barabarani, usijilazimishe kupita kwa miguu kamwe: ni muhimu kuhama mapema kwenda mahali pa juu pasipofikiwa na maji." },
  { id:44, topic:"Mafuriko ya ghafla", emoji:"⛈️",
    question:"Mahali ulipo kuna jua, lakini mbali juu ya milima unaona mawingu meusi na kusikia ngurumo. Unapokuwa karibu na mto, unafanya nini?",
    choices:["Juu yako kuna jua, kwa hiyo unaendelea kucheza mtoni kama kawaida","Mvua kubwa inanyesha juu (milimani), na sasa hivi yaweza kuja ghafla maji ya kutisha kwa kasi kubwa (mafuriko ya ghafla), kwa hiyo jiweke mbali na mto mara moja na ukimbilie mahali pa juu","Unasubiri kwa utulivu maji ya mto yawe na matope","Unaingia mtoni kupoza mwili"],
    answerIndex:1,
    explanation:"Jambo la kutisha kuhusu mito ni kwamba, hata mahali ulipo kukiwa na jua, mvua kubwa inaponyesha 'juu, milimani' ambapo mto unaanzia, kiasi kikubwa cha maji kilichokusanyika hapo huwa donge la kasi ya kutisha kama tsunami na hukimbilia chini ya mto mara moja. Hii huitwa 'mafuriko ya ghafla'. Ukiona mawingu meusi juu ya milima, ukasikia ngurumo, ukaona maji ya mto yakiwa na matope ghafla, au ukaona matawi mengi zaidi yakisombwa, hizo ni ishara za asili kwamba mafuriko makubwa yanakaribia. Toka mtoni na hamia mahali pa juu hata sekunde moja mapema." },
  { id:45, topic:"Radi na miti", emoji:"🌩️",
    question:"Kumemulika na radi kali imepiga. Ukiwa nje, je, ni salama kujikinga na mvua 'chini ya mti mrefu moja kwa moja'?",
    choices:["Chini ya mti ni kama paa, kwa hiyo ni mahali salama zaidi duniani","Hatari sana. Radi hupiga vitu virefu kwa urahisi, na umeme uliopiga mti huruka kwa mtu aliyesimama chini yake moja kwa moja (mpigo wa kando)","Ukipanda mti radi haitakupiga","Kuinua mwavuli juu na kusimama chini ya mti"],
    answerIndex:1,
    explanation:"Radi inapopiga, kujikinga chini ya mti mrefu ni jambo ambalo kamwe usifanye. Radi ina tabia ya kupiga 'kitu kirefu na chenye ncha zaidi' katika eneo. Kwa hiyo uwezekano wa radi kupiga mti ni mkubwa sana, na umeme mkubwa uliopiga mti hupita kwa urahisi zaidi kupitia mwili wa mtu aliye karibu sana kuliko kupitia mti, hivyo umeme 'huruka kando' kutoka mti kwenda kwa mtu. Hii huitwa 'mpigo wa kando'. Ni lazima daima ujiweke mbali na mti kwa angalau mita 4." },
  { id:46, topic:"Salama kutoka radi", emoji:"🚗",
    question:"Radi inapodunda kwa nguvu pande zote, ni wapi mahali salama zaidi kujilinda?",
    choices:["Kusimama katikati ya uwanja tambarare na wazi","Ndani ya jengo imara la saruji au matofali, au ndani ya gari lililofunikwa kabisa kwa chuma","Ndani ya hema kubwa","Ndani ya maji ya bwawa au mto"],
    answerIndex:1,
    explanation:"Salama zaidi kujilinda na radi ni kuingia ndani ya jengo imara. Umeme hutoroka kwenda ardhini kupitia kuta na nguzo za jengo, kwa hiyo haufiki watu walio ndani. Pia, gari au basi lililofunikwa kabisa kwa chuma (feleji) ni salama sana. Hata radi ikipiga gari, umeme hupita vizuri kupitia mwili wa nje na hutoroka kutoka matairi kwenda ardhini, kwa hiyo watu walioketi ndani hawana jeraha. Kinyume chake, kusimama peke yako katikati ya uwanja wazi ni hatari sana, kwa sababu wewe mwenyewe unakuwa 'kitu chenye ncha kirefu zaidi' na kuita radi." },
  { id:47, topic:"Moshi wa moto na mkao", emoji:"🚪",
    question:"Moto umeibuka ndani ya jengo. Chumba kinapojaa 'moshi', unapaswa kutorokaje?",
    choices:["Kukimbia kwa kifua kilichonyooka na mkao wa juu ili uone moshi vizuri","Moshi ni mwepesi kuliko hewa na 'hujikusanya juu', kwa hiyo ili kupumua hewa safi karibu na sakafu, toroka chini, ukitambaa sakafuni","Kuchuchumaa kwenye kona ya chumba na kusubiri moshi uondoke","Kuvuta pumzi kubwa kuelekea dari"],
    answerIndex:1,
    explanation:"Kama ulivyojifunza katika paketi ya mekanika iliyopita, hewa ya joto na moshi vina tabia ya lazima ya kuwa 'vyepesi kuliko hewa ya baridi, kwa hiyo hupanda juu zaidi na zaidi'. Kwa sababu hii, katika chumba kinachowaka, moshi wa kutisha na gesi zenye madhara hujikusanya kutoka darini kuelekea chini. Kinyume chake, karibu na sakafu (ndani ya sentimita 30 kutoka ardhini) hubaki hadi mwisho hewa safi unayoweza kuipumua. Unapotoroka kupitia moshi, dumisha 'mkao wa chini', ukipinda mgongo na kutambaa sakafuni huku ukielekea mlangoni: hii ni kanuni ya kuokoka inayoshirikiwa duniani kote." },
  { id:48, topic:"Usivute moshi", emoji:"😷",
    question:"Unapotoroka kupitia moshi wa moto, ni jambo gani jema kufanya ili usivute moshi?",
    choices:["Kubandika taulo kavu mdomoni","Kufunika mdomo na pua yako kwa imara kwa kitambaa au nguo iliyolowa maji, na kutoroka huku ukipumua kwa utulivu na kwa pumzi fupi","Kupumua huku ukipiga kelele","Kutofanya chochote na kukimbia tu hivyo"],
    answerIndex:1,
    explanation:"Vifo vingi katika moto havitokani na kuchomwa na miali, bali na kuvuta gesi zenye madhara katika moshi, kama 'monoksidi kaboni', na kupoteza fahamu. Ili usivute moshi, ni vyema kubandika kwa nguvu leso au nguo iliyolowa maji mdomoni na puani. Nafasi nyembamba katika kitambaa kilicholowa hufanya kazi ya 'kichujio' kinachonasa masizi yenye madhara na cheche za moto katika moshi. Na badala ya kukimbia huku ukivuta pumzi kubwa za kuhema, pumua kwa utulivu na kwa pumzi fupi kupitia leso huku ukielekea mlangoni kwa utulivu." },
  { id:49, topic:"Maporomoko ya ardhi", emoji:"⛰️",
    question:"Baada ya mvua kubwa kunyesha kwa siku nyingi, kwa nini ni hatari kutembea karibu na mlima au chini ya genge?",
    choices:["Kwa sababu mlima unakuwa baridi na unapata mafua","Kwa sababu udongo wa ardhi unanyonya kiasi kikubwa cha maji na kuwa kama matope, na mteremko wa mlima waweza kuporomoka mara moja (maporomoko ya ardhi)","Kwa sababu wanyama wa mlimani hukasirika na kushuka","Kwa sababu ardhi hukauka na kuwa ngumu"],
    answerIndex:1,
    explanation:"Udongo na mawe ya ardhi hushikamana kwa imara yakiwa na unyevu wa kadiri, lakini mvua kali inaponyesha kwa siku nyingi, maji mengi mno hujikusanya katika nafasi za udongo na huwa kama supu ya majimaji. Udongo uliokuwa mzito hauwezi kustahimili mvuto wa nchi, na katika muda fulani, bila taarifa, mlima mzima huporomoka kwa kasi ya kutisha. Hii huitwa 'maporomoko ya ardhi'. Usikaribie kamwe mlima au genge wakati mvua inanyesha au mara tu baada ya mvua kukoma. Kama maji ya matope yakibubujika kutoka ardhini, au ukasikia sauti ya mawe yakibingirika, hizo ni ishara za hatari kwamba mlima u karibu kuporomoka." },
  { id:50, topic:"Tsunami", emoji:"🌊",
    question:"Unapokuwa karibu na bahari, ardhi inatetemeka kwa nguvu kwa mtikisiko (tetemeko la ardhi). Ni jambo gani muhimu zaidi la kufanya mara tu baada yake?",
    choices:["Maji ya bahari yaweza kurudi nyuma na labda utavua samaki, kwa hiyo unakaribia ufuoni","Ukuta mkubwa wa maji (tsunami) waweza kuja kutoka bahari ya mbali kwa kasi ya kutisha, kwa hiyo jiweke mbali na bahari hata sekunde moja mapema na ukimbilie 'mlima mrefu au mwinuko imara'","Kuchimba shimo ufuoni wa mchanga na kujificha","Kupanda mashua na kuelekea bahari ya mbali"],
    answerIndex:1,
    explanation:"Tetemeko kubwa linapotokea chini ya bahari, ardhi ya sakafu ya bahari husogea kwa nguvu, hivyo donge zima la maji ya bahari juu yake huwa wimbi kubwa linalokimbilia ufuoni. Hii ndiyo 'tsunami'. Tsunami ni tofauti kabisa na wimbi la kawaida: ni 'ukuta mkubwa wa maji' ulioungana kutoka sakafu ya bahari hadi uso. Nguvu yake ni kubwa ya kutosha kuangusha nyumba na miti chini mara moja. Kabla tsunami haijafika, nyakati nyingine maji ya pwani hurudi nyuma kwa kasi kwa mvumo wa ajabu, lakini ukiona hivyo na kuona ni jambo la kufurahisha na kukaribia, hutaokoka kamwe. Ukihisi mtetemeko ufukweni, usishike chochote na ukimbilie mahali pa juu sasa hivi." },
  { id:51, topic:"Vimbunga na upepo mkali", emoji:"🌪️",
    question:"Upepo mkali wa ghafla wa kutisha, au upepo mkali unaozunguka kwa kimbunga (tornado), unakukaribia. Ni wapi salama zaidi kujificha?",
    choices:["Kushikilia matawi ya mti mkubwa ulio nje","Kuingia jengo imara la saruji au kama hilo lisilo na vioo vya madirisha, kujikunja kwenye kona ya ukuta na kulinda kichwa","Kufungua mwavuli nje na kustahimili upepo","Kupanda paa tambarare"],
    answerIndex:1,
    explanation:"Hofu halisi ya upepo mkali au kimbunga si nguvu ya upepo wenyewe tu, bali ni kwamba vitu vinavyopeperushwa na upepo — 'mabango, vigae, matawi, mawe' — huruka kwako kwa kasi ya kutisha kama risasi. Vikikupiga mwilini, hukujeruhi vibaya. Pia, kioo cha dirisha la jengo kikivunjika kwa shinikizo la upepo, vipande vyake hutawanyika ndani ya chumba na ni hatari sana. Upepo mkali ukija, ingia jengo imara mara moja na uchuchumae 'katikati ya chumba kilicho mbali zaidi na madirisha, au kwenye kona ya ukuta'. Kisha shika kichwa chako kwa mikono yote miwili na ujikunje ukiwa mdogo ili kulinda mwili." },
  { id:52, topic:"Dhoruba ya mchanga na majivu", emoji:"🌋",
    question:"'Dhoruba ya mchanga' kali kiasi cha kufanya anga liwe jeusi, au 'majivu ya volkano' kutoka volkano, yanaponyesha, unapaswa kulinda nini?",
    choices:["Kulinda nyayo za miguu ili viatu visichafuke","Ili usivute mchanga au majivu laini na kuumiza mapafu yako, au yasiingie machoni na kuyajeruhi, funika uso wako (mdomo, pua, macho) vizuri kwa kitambaa kilicholowa","Kulinda fedha iliyo mfukoni","Kuimba wimbo kwa sauti kubwa ili kupuliza majivu mbali"],
    answerIndex:1,
    explanation:"Mchanga wa dhoruba ya mchanga na majivu yanayonyesha kutoka volkano ni kama 'vipande vidogo vya kioo au chembe za mawe', laini sana na vyenye ncha. Ukiyavuta moja kwa moja kupitia mdomo au pua, kina cha mapafu hujeruhiwa na huwezi kupumua, hivyo unapata ugonjwa mbaya. Na yakiingia machoni, maumivu makali yanakuzuia kuyafungua. Dhoruba ya mchanga au majivu yanaponyesha, funika mdomo na pua yako kwa imara kwa kitambaa au nguo yenye unyevu, na linda macho kupitia kitambaa au yafumbe kabisa, ukitengeneza kizuizi ili chembe laini zisiingie mwilini mwako. Kisha stahimili bila kusonga mahali salama ndani au nyuma ya kizuizi hadi chembe zipite." },
  { id:53, topic:"Kutoona kabisa", emoji:"🌨️",
    question:"Ukiwa unatembea nje, ghafla kunatokea 'ukungu' mzito au 'dhoruba ya theluji' kali, na pande zote zinakuwa nyeupe hivyo huoni chochote. Unafanya nini?",
    choices:["Unaamini hisia zako na, kiwe kitakavyo, unaendelea kukimbia mbele","Kusonga kwa kujilazimisha waweza kukufanya uanguke kutoka genge au upotee na ukwame, kwa hiyo jikinge nyuma ya jiwe salama au kama hilo na subiri bila kusonga hadi uoni uwe wazi","Kukimbia kwa mzunguko huku ukipiga kelele","Kulala chini na kusinzia"],
    answerIndex:1,
    explanation:"'Kutoona kabisa', wakati huwezi tena kuona mandhari iliyokuzunguka porini, ni mtego wa kutisha unaoweza kugharimu hata watu wazima maisha yao. Ukiwa katika ukungu au dhoruba ya theluji ukianza kutembea ukiamini hisia, ukidhani 'pengine ni huku', hupoteza fahamu ya upande unaoutazama, huwezi kurudi ulipoanzia, au unaanguka kichwa mbele kutoka ukingo wa genge bila kutambua. Unapofikia hali ya kutoona hatua moja mbele, jibu sahihi ni kwanza usijilazimishe hatua hata moja. Jikinge nyuma ya jiwe salama linalokukinga na upepo na baridi, na subiri kwa subira hadi ukungu upungue au dhoruba ya theluji ikome." },
  { id:54, topic:"Kupatwa kwa jua na macho", emoji:"👁️",
    question:"Wakati wa tukio nadra la angani kama 'kupatwa kwa jua', ambapo umbo la jua hubadilika, je, ni sawa kutazama jua moja kwa moja kwa macho yako?",
    choices:["Kwa kuwa ni tukio nadra, unapaswa kufungua macho wazi na kulitazama vizuri","Hapana kabisa. Mwanga wa jua ni mkali sana, na kulitazama moja kwa moja huteketeza chembechembe muhimu ndani ya jicho, kwa hatari ya kutoona tena kamwe (upofu)","Ukivaa miwani ya jua, ni salama kutazama kwa saa nyingi upendazo","Ni sawa kutazama moja kwa moja jua lililoakisiwa kwenye dimbwi"],
    answerIndex:1,
    explanation:"Jua hutoa mwanga wa ajabu unaohuisha kila uhai duniani, lakini nishati ya mwanga huo ni 'kali ya kutosha kuharibu jicho la mwanadamu kwa kitambo'. Hata wakati wa kupatwa jua likionekana limefunikwa kidogo na giza zaidi, nguvu ya mwanga unaotoka haibadiliki. Ukitazama jua moja kwa moja kwa jicho tupu, chembechembe muhimu zaidi za jicho zinazoweka mwelekeo (retina) huteketea, sawasawa kama kioo cha kukuza kinavyochoma karatasi. Chembechembe zilizoteketea hazirudi kamwe katika hali ya kawaida, na waweza kupoteza uoni maisha yako yote. Unapotazama jua, daima fuata kanuni ya kutumia kifaa maalum salama." },
  { id:55, topic:"Matope ya kuzama", emoji:"🆘",
    question:"Ukiwa unatembea, ardhi chini ya miguu yako inakuwa kama matope na mwili wako unaanza kuzama chini zaidi na zaidi (matope ya kuzama). Unasongaje?",
    choices:["Unajaribu kuvuta miguu kwa kupambana na kusonga miguu kwa nguvu","Kadiri unavyopambana ndivyo unavyozama zaidi, kwa hiyo usiwe na hofu: egemeza mwili nyuma ili kueneza 'eneo' lako, lala uso juu na uelee ukisubiri msaada","Unachimba matope mengi kwa mikono","Unajifunga uzito mwilini"],
    answerIndex:1,
    explanation:"Unapokwama katika matope ya kuzama au matope ya kina, jambo baya zaidi kufanya ni 'kupambana kwa nguvu'. Ukijaribu kuvuta mguu mmoja kwa nguvu juu, kiasi hicho hicho 'uzito wote wa mwili (nguvu kubwa) hujikita kwenye mguu mwingine', hivyo mwili wako huzama zaidi chini. Ukikwama, kwanza simamisha msogeo na ulaze sehemu ya juu ya mwili nyuma juu ya matope, ukienea kama nyota. Kama ulivyojifunza katika paketi ya mekanika iliyopita, kwa kueneza uzito wako kwenye eneo pana, unazama kwa shida zaidi kwenye matope na waweza kuelea. Katika hali hiyo, ita msaada kwa utulivu." },
  { id:56, topic:"Wanyama wa porini", emoji:"🐾",
    question:"Ukiwa unatembea nje, mbele yako anatokea 'mbwa wa porini au mnyama mkali' wa kutisha akionyesha meno. Unajiwekaje mbali?",
    choices:["Kugeuza mgongo na kukimbia kwa kasi yote huku ukipiga kelele","Usikimbie kamwe. Wanyama wana silika ya kufukuza kinachokimbia, wakidhani ni 'mawindo', kwa hiyo usikutane macho naye na rudi nyuma kimyakimya ili ujiweke mbali","Kumkazia macho na kumtaka apigane","Kulala chini na kujifanya umekufa"],
    answerIndex:1,
    explanation:"Wanyama wala nyama wa porini na mbwa wenye njaa ni wepesi zaidi kuliko mwanadamu. Mnyama anapotokea mbele yako, kama katika hofu unageuza mgongo na 'kukimbia kwa kasi yote', swichi ya kipori katika ubongo wa mnyama — 'kufukuza na kumaliza mawindo yanayokimbia' — huwaka, naye hukushambulia kwa kasi ya kutisha. Ukikutana na mnyama wa porini, kwanza tuliza moyo bila kupiga kelele, geuza macho kidogo ili usimchokoze, na bila kumwonyesha mgongo, 'rudi nyuma kimyakimya na polepole sana, hatua moja kwa wakati' ili kuongeza umbali. Kujua silika za wanyama ni hekima ya ulinzi." },
  { id:57, topic:"Mizinga ya nyuki", emoji:"🐝",
    question:"Msituni, unakuta 'mzinga wa nyuki' mkubwa kwenye mti. Kuzunguka kwake nyuki wanaruka. Unapaswa kufanya nini?",
    choices:["Kwa kuwa ni nadra, unarusha jiwe ili kuangusha mzinga","Usikaribie kamwe. Ukipiga kelele au ukapambana, nyuki hudhani 'mzinga unashambuliwa' na hukushambulia kwa kundi, kwa hiyo ondoka mahali hapo kimyakimya kwa mkao wa chini","Kupunga mikono kwa nguvu ili ufanye urafiki na nyuki","Kusimama chini ya mzinga moja kwa moja na kuutazama"],
    answerIndex:1,
    explanation:"Wadudu kama nyuki kwa kawaida hawashambulii binadamu bila sababu. Lakini binadamu anapokaribia 'mzinga' wao, ambao ni watoto wao na nyumba yao, huingia katika hali ya tahadhari kali. Ndipo binadamu akipiga kelele, akapunga mikono kwa nguvu, au akarusha mawe, nyuki huamua 'adui amekuja kuharibu mzinga!' na hutuma kwa wenzao wote ishara maalum ya sumu, na mamia yao hushambulia kwa kundi kuuma kwa mara moja. Kuumwa mara nyingi na sumu ya nyuki kwaweza kukugharimu maisha. Ukikuta mzinga, shika pumzi kimyakimya, shusha mkao, na ondoka mahali hapo polepole." },
  { id:58, topic:"Maji baada ya maafa", emoji:"🚰",
    question:"Baada ya mvua kubwa au mafuriko, kutoka bomba au kisima cha nyumbani kwako kumetoka 'maji safi yaliyo wazi'. Je, ni sawa kunywa maji haya kama yalivyo?",
    choices:["Yakionekana wazi na safi, hayana vijidudu, kwa hiyo waweza kuyanywa kama yalivyo","Usiyanywe kamwe kama yalivyo. Maji baada ya maafa yana uwezekano mkubwa sana wa kuchanganyikana na vijidudu na virusi vya matope vya kutisha visivyoonekana, kwa hiyo daima 'yachemshe kwa nguvu juu ya moto' kabla ya kunywa","Kuyaweka juani sekunde 10 kisha kunywa","Yanakuwa salama ukichanganya sukari"],
    answerIndex:1,
    explanation:"Kama ulivyojifunza pia katika paketi ya kwanza, maji baada ya mvua kubwa au mafuriko makubwa hayapaswi kunywewa kama yalivyo kamwe, yawe wazi na safi kiasi gani. Hii ni kwa sababu nguvu kali ya mafuriko ina uwezekano mkubwa sana wa kufanya maji machafu ya zamani ya chini ya ardhi na uchafu wa mifugo yarudi nyuma na kuchanganyikana katika visima na mabomba ya maji. Kuyanywa kama yalivyo husababisha maambukizi makali na kuhara, kuhatarisha maisha yako. Kiu yako iwe kali kiasi gani, fuata hekima ya kuweka maji ya wakati wa maafa juu ya moto mara moja na kuyachemsha hadi mapovu yatoke kwa nguvu, ukiangamiza vijidudu." },
  { id:59, topic:"Barabara zilizofurika", emoji:"🦯",
    question:"Baada ya mvua kubwa, barabara imejaa maji pomoni na huoni ardhi kabisa. Unapolazimika kabisa kupita hapa, unatembeaje?",
    choices:["Kwa kuwa maji ni ya kupendeza, unavua viatu na kuvuka kwa kukimbia kwa furaha","Mashimo ya kina au kioo chenye ncha vyaweza kuwa vimefichwa (havionekani) chini ya maji, kwa hiyo gonga ardhi chini ya miguu yako kwa 'fimbo ya mbao' ndefu na imara ili kuhakikisha, na songa mbele hatua kwa hatua","Kufumba macho na kutembea moja kwa moja","Kumwomba mtu aliye nyuma akubebe mgongoni uvuke"],
    answerIndex:1,
    explanation:"Kutembea barabara ambayo ardhi yake imefichwa na dimbwi au mafuriko ni hatari sawasawa na kutembea macho yamefumbwa. Chini ya maji yaweza kuwa vipande vya chupa iliyovunjika na misumari yenye ncha, na mashimo ya maji taka ya kina yaliyotoka vifuniko, au mitaro ya kina ardhi yake imemomonyoka, 'yamefichwa kabisa' yakikusubiri. Ukikanyaga bila uangalifu, unaanguka chini ya shimo na kusombwa, au unapata jeraha la kina na kuugua. Unapolazimika kabisa kutembea, daima vaa viatu, tumia fimbo ndefu ya mbao kama mkongojo, na kabla ya kila hatua, gonga ili kuhakikisha kama 'ardhi inayofuata ni ngumu na salama': huo ndio mtindo sahihi wa kutembea unaolinda maisha yako." },
  { id:60, topic:"Kuangalia na kutabiri", emoji:"🧠",
    question:"Popote ulipo duniani, ni 'nguvu gani ya akili' iliyo muhimu zaidi kulinda kwa hakika maisha yako na ya familia yako kutoka majanga ya asili ya kutisha?",
    choices:["Nguvu ya kuendelea kusubiri mahali pamoja, bila kufanya chochote, hadi mtu aje kusaidia","Nguvu ya kuangalia vizuri 'sauti, rangi, harufu, na msogeo wa viumbe hai' katika asili iliyokuzunguka, kutabiri mapema hatari inayofuata, na kusonga mapema kwa hekima yako mwenyewe kabla hali haijawa hatari","Nguvu ya kuzoeza misuli ya miguu yako iwe imara kuliko ya mtu yeyote","Nguvu ya kudhani bila kujali kwamba huwezi kupatwa na madhara"],
    answerIndex:1,
    explanation:"Hongera! Kwa hili maswali 20 ya paketi ya tatu yamekamilika. Mbele ya majanga makubwa ya asili yanayosababishwa na Dunia, binadamu hawezi kamwe kushinda kwa nguvu ya mikono au kasi ya miguu peke yake. Lakini sisi binadamu tuna 'hekima'. Ukiangalia asili vizuri, Dunia daima hutoa 'ishara za awali' kwamba hatari iko karibu — maji ya mto kuwa na matope, mawe ya mlima kuanguka, kuhisi baridi ya kutetemeka, wanyama kuvurugika. Nguvu ya kutambua haya mapema iwezekanavyo, kutabiri kichwani 'mahali pale pako karibu kuwa hatari', na kuhamia mahali salama kwa miguu yako mwenyewe kabla mtu hajakuambia, ndiyo hirizi yenye nguvu zaidi duniani inayokuokoa wewe na wapendwa wako." },
  { id:61, topic:"Kuhesabu kwa Vikundi", emoji:"🥔",
    question:"Kuna mifuko 3 ya viazi, kila mfuko una viazi 10, pamoja na viazi 4 vilivyotawanyika. Kuna jumla ya viazi vingapi?",
    choices:["Viazi 7","Viazi 13","Viazi 34","Viazi 43"],
    answerIndex:2,
    explanation:"Unapohesabu, kutengeneza 'vikundi vya 10' ni haraka zaidi na hupunguza makosa kuliko kuhesabu kimoja kimoja. Mifuko 3 ya 10 maana yake ni 10, 20, 30 — hayo pekee ni 30. Ukijumlisha vile 4 vilivyotawanyika, 30 jumlisha 4 ni 34. Hekima hii ya 'mfumo wa kumi' ya kuelewa namba kubwa vizuri ni ujuzi wa msingi unaotumika kila siku katika biashara na hesabu duniani kote." },
  { id:62, topic:"Kutoa", emoji:"🐭",
    question:"Ulikuwa na maharagwe 25 ya thamani kwa jumla, lakini panya alikula 10 kati yake. Yamebaki mangapi?",
    choices:["Maharagwe 5","Maharagwe 10","Maharagwe 15","Maharagwe 35"],
    answerIndex:2,
    explanation:"Ili kukokotoa kilichobaki baada ya sehemu ya jumla kuondolewa, tunatumia 'kutoa'. Namba 25 inaweza kuelezwa kama 'vikundi viwili vya 10 na 5 vilivyotawanyika'. Ukiondoa kikundi kimoja cha 10, unabaki na 'kikundi kimoja cha 10 na 5 vilivyotawanyika', yaani 15. Kuweza kukokotoa vizuri ni kiasi gani chakula au rasilimali kimepungua na kimebaki kiasi gani ni hekima muhimu ya kuendesha maisha yako kwa mpango." },
  { id:63, topic:"Kuzidisha", emoji:"🛒",
    question:"Swali la ununuzi! Unataka kununua vifaa 3 vyenye manufaa, kila kimoja kinagharimu sarafu 20. Utalipa jumla kiasi gani?",
    choices:["Sarafu 23","Sarafu 40","Sarafu 60","Sarafu 80"],
    answerIndex:2,
    explanation:"Namba ileile inaporudiwa mara kwa mara, tunatumia 'kuzidisha'. Vifaa 3 vya sarafu 20 kila kimoja maana yake ni 20 imejumlishwa mara tatu. 20 jumlisha 20 ni 40, na ukijumlisha 20 tena unapata jumla ya 60. Unaponunua na kuuza dukani, kama hauna uwezo huu wa kujumlisha kiasi pamoja kichwani, unaweza kutozwa zaidi ya inavyostahili na kudanganywa bila kutambua. Uwezo wa kukokotoa ni ngao inayolinda pesa zako." },
  { id:64, topic:"Kugawanya", emoji:"➗",
    question:"Unataka kugawa mikate 12 bapa kwa watoto 4 kwa usawa na sawasawa kabisa. Kila mtoto atapata mingapi?",
    choices:["Kila mmoja 2","Kila mmoja 3","Kila mmoja 4","Kila mmoja 6"],
    answerIndex:1,
    explanation:"Kugawa vitu kwa haki kwa wote ni wazo la 'kugawanya'. Ukigawa mikate 12 kwa usawa kwa watoto 4, kila mmoja 2 ni '2 mara 4 ni 8', na mkate unabaki. Kugawa kila mmoja 3 ni '3 mara 4 ni 12', ambacho kinatumia mikate yote sawasawa. Hekima ya kukokotoa namba vizuri na kuzigawa — ili hakuna apate zaidi wakati mwingine anahuzunika — ni ujuzi muhimu sana wa kuishi pamoja kwa amani." },
  { id:65, topic:"Kusoma Saa", emoji:"⏰",
    question:"Swali la saa! Mshale mrefu unapofika '12', inakuwa saa kamili. Sasa mshale mrefu unaonyesha '9'. Baada ya dakika ngapi itakuwa saa kamili?",
    choices:["Baada ya dakika 3","Baada ya dakika 15","Baada ya dakika 30","Baada ya dakika 45"],
    answerIndex:1,
    explanation:"Uso wa saa umejengwa kwa kanuni kwamba 'dakika 5' hupita kila namba zinaposonga moja. Ili mshale mrefu uende kutoka 9 hadi alama kamili ya 12, namba lazima zisonge hatua tatu: 10, 11, 12. Dakika tano zikirudiwa mara tatu zinatoa 5, 10, 15, hivyo jibu ni 'baada ya dakika 15'. Jifunze kutoa vizuri kwa namba za saa, ili kupanga ni muda gani umebaki hadi miadi, au hadi usiku uingie." },
  { id:66, topic:"Kulinganisha Uzito", emoji:"⚖️",
    question:"Swali la kulinganisha uzito! Jiwe A ni zito kuliko jiwe B. Jiwe B ni zito kuliko jiwe C. Kati ya mawe haya matatu, lipi ni 'jepesi zaidi'?",
    choices:["Jiwe A","Jiwe B","Jiwe C","Yote ya uzito sawa"],
    answerIndex:2,
    explanation:"Hii ni fumbo la 'mantiki' ambapo unapanga masharti kichwani ili kufikia jibu sahihi. Kwanza, 'A ni zito kuliko B', hivyo A iko juu na B chini yake. Halafu, 'B ni zito kuliko C', hivyo C inaenda chini ya B. Ukizipanga kwa mpangilio kutoka juu hadi chini, unapata A (zito zaidi), B katikati, na C (jepesi zaidi) chini. Hivyo jepesi zaidi ni 'jiwe C'. Kuza uwezo wa kujenga kwa maneno na kuamua vizuri hata wakati vitu halisi havipo mbele yako." },
  { id:67, topic:"Kuunganisha Maumbo", emoji:"📐",
    question:"Una karatasi mbili za 'pembetatu yenye pembe ya mraba'. Ukiunganisha pande zao ndefu (upande wa mteremko) sawasawa kabisa, umbo gani litaundwa?",
    choices:["Duara","Umbo la pande nne (mstatili au mraba)","Pembetano","Umbo la nyota"],
    answerIndex:1,
    explanation:"Hii ni hekima ya 'utambuzi wa nafasi' — kusogeza na kuunganisha maumbo kichwani. Hata pembetatu yenye pembe ya mraba yenye ncha ya mteremko inaweza kugeuka kuwa umbo la pande nne (mstatili au mraba) lenye pembe zote zilizonyooka, ukiandaa mbili zinazofanana na kuunganisha pande zao ndefu za mteremko zikiangaliana vizuri. Kujua sifa za maumbo ni muhimu sana kupanga mizigo kwenye sanduku bila nafasi zilizopotea, au kubuni msingi imara wa jengo." },
  { id:68, topic:"Kufichua Uongo", emoji:"🕵️",
    question:"Fumbo la mantiki la kumtafuta mwongo. Kuna wavulana wawili, A na B. A anasema: 'Mimi sikula peremende.' B anasema: 'A alikula peremende.' Kama anachosema A ni [kweli], je B anasema uongo au kweli?",
    choices:["B anasema uongo","B anasema kweli","Wote wawili wanasema kweli","Haiwezi kubainika"],
    answerIndex:0,
    explanation:"Hili ni fumbo la kutafuta utata (kile kisichoendana). Sharti linasema 'anachosema A ni kweli'. Maana yake A ni mtu mwaminifu ambaye kweli hakula peremende. Lakini B anasema kinyume kabisa: 'A alikula peremende.' Kwa kuwa B anamshtaki A mkweli kuwa mwongo, basi maneno ya B ndiyo 'uongo (kosa)'. Uwezo wa kupambanua maneno ya nani ni sahihi na ya nani yanapingana ni muhimu sana kwa kujilinda." },
  { id:69, topic:"Mfululizo wa Namba", emoji:"🧮",
    question:"Swali la mtindo. Namba '1, 3, 5, 7, 9' zimepangwa mfululizo. Kufuata kanuni hii, namba gani inafuata baada ya 9?",
    choices:["10","11","12","15"],
    answerIndex:1,
    explanation:"Hii ni mazoezi ya ubongo ya kugundua mtindo (mfululizo wa namba) ambapo namba zinaongezeka kwa kanuni isiyobadilika. Ukiangalia vizuri, kutoka 1 hadi 3 inaongezeka '2'. Kutoka 3 hadi 5 pia '2'. Yaani safu hii ya namba inafuata kanuni (namba witiri) ya 'kuongezeka 2 kila hatua'. Ili kujua namba baada ya 9, jumlisha tu '2' ya kanuni, hivyo 9 jumlisha 2 ni 11. Uwezo wa kusoma mapema jinsi kanuni inavyobadilika unakufanya hodari wa kutabiri yajayo." },
  { id:70, topic:"Fumbo la Kukata", emoji:"🔪",
    question:"Ulikata fimbo moja kwa kisu moja kwa moja 'mara 3'. Fimbo imegawanyika vipande vingapi kwa jumla?",
    choices:["Vipande 2","Vipande 3","Vipande 4","Vipande 5"],
    answerIndex:2,
    explanation:"Hili ni fumbo ('tatizo la kupanda miti') la kuwazia uhusiano kati ya idadi ya mikato na idadi ya vipande vinavyotengenezwa. Kukata fimbo isiyokatwa mara moja kunatoa 'vipande 2'. Mkato wa pili unatoa 'vipande 3'. Na mkato wa tatu unaongeza sehemu nyingine, na kufanya 'vipande 4' kwa jumla. Ni kanuni ya kufurahisha ya hisabati kwamba idadi ya vipande daima ni 'moja zaidi' ya idadi ya mikato. Jifunze kukokotoa matokeo vizuri kichwani kabla ya kuharibu kitu halisi." },
  { id:71, topic:"Vizidishi", emoji:"📊",
    question:"Kuna ndoo za kuhifadhi maji. Ndoo A inabeba maji 'mara 3' zaidi ya ndoo B. Ndoo B ina lita 2 za maji. Ndoo A inabeba lita ngapi za maji?",
    choices:["Lita 3","Lita 5","Lita 6","Lita 8"],
    answerIndex:2,
    explanation:"'Mara 3' ya namba maana yake ni kuunganisha tatu zinazofanana — kwa maneno mengine 'kuijumlisha mara tatu' au 'kuizidisha kwa 3'. Ndoo B ina lita 2, na A ni mara 3 ya hiyo, hivyo ni sehemu tatu za lita 2. Ukikokotoa 2 jumlisha 2 jumlisha 2, au 2 mara 3, jibu ni 6. Katika maisha ya kila siku mara nyingi tunasema 'mara 3 ya uzito', 'mara 3 ya eneo', na kujua dhana ya vizidishi kunakuwezesha kukadiria kiasi cha vitu kwa usahihi." },
  { id:72, topic:"Mpangilio wa Foleni", emoji:"👥",
    question:"Watoto sita wamesimama katika foleni moja iliyonyooka. Kwa mtoto aliye 'wa nne kutoka mbele', kuna watoto wangapi nyuma yake?",
    choices:["Mtoto 1","Watoto 2","Watoto 3","Watoto 4"],
    answerIndex:1,
    explanation:"Hili ni fumbo la kuelewa vizuri uhusiano kati ya idadi ya jumla na nafasi katika mpangilio. Kuna watoto 6 kwa jumla. Ukihesabu kutoka mbele, ukimjumuisha mtoto wa nne mwenyewe, hadi hapa watoto 4 wametumika. Ukitoa hawa 4 kutoka jumla ya 6, wanabaki 2. Yaani nyuma ya mtoto wa nne wamesimama wa tano na wa sita — 'watoto 2'. Uwezo wa kuelewa nafasi katika foleni kama namba kwa utulivu ni muhimu kudumisha mpangilio kwa haki katika jamii." },
  { id:73, topic:"Kupima Urefu", emoji:"📏",
    question:"Swali la kupima. Ulipima meza ukitumia 'upana wa kiganja chako kilichofunguliwa, kutoka kidole gumba hadi kidole cha mwisho' kama kipimo, na ulipata sawasawa vipimo 5. Ni kanuni gani muhimu ya njia hii ya kupima?",
    choices:["Kubadilisha upana wa kiganja chako kuwa mkubwa au mdogo kila mara unapopima","Ili kulinganisha urefu vizuri, kupima daima kwa 'upana uleule (kipimo kilekile)', vikiunganishwa bila nafasi","Kuhesabu kwa makadirio ukiwa umefumba macho","Kupima kwa wayo wa mguu badala ya kiganja"],
    answerIndex:1,
    explanation:"Katika enzi bila chombo cha kupima (rula), watu walipima urefu kwa mikono na miguu yao. Kanuni muhimu zaidi wakati huo ni 'kuweka kipimo cha urefu kikiwa thabiti daima kwa ukubwa uleule kabisa'. Kama upana wa kiganja chako unatofautiana kila mara, hata ukihesabu vipimo 3 au 5, hakuna atakayejua urefu halisi ni kiasi gani. Vipimo vya pamoja kama 'sentimita' vilizaliwa duniani kote hasa kama hekima ili wote wafanye biashara kwa haki kwa kiwango kilekile." },
  { id:74, topic:"Thamani ya Pesa", emoji:"💰",
    question:"Una sarafu ya thamani 10 (sarafu moja yenye thamani 10). Uliibadilisha na sarafu kumi za thamani 1 (sarafu zenye thamani 1 kila moja) kutoka kwa rafiki yako. 'Thamani ya jumla' ya pesa uliyonayo (uwezo wake wa kununua vitu) imebadilikaje?",
    choices:["Idadi imepanda hadi sarafu 10, hivyo thamani pia imeongezeka mara 10","Umbo tu limebadilika — sarafu moja imegawanyika kuwa kumi — lakini thamani ya jumla ya pesa ni 'ileile kabisa (haijabadilika)'","Sarafu ya 10 ni kubwa zaidi, hivyo umepata hasara na thamani imepungua","Thamani ya pesa imekuwa sufuri"],
    answerIndex:1,
    explanation:"Hii ni hekima kuhusu kanuni muhimu ya pesa: 'kuhifadhi thamani'. Sarafu moja ya 10, na sarafu kumi za 1, zinaonekana tofauti kabisa kwa idadi na umbo, lakini thamani ya jumla wanayowakilisha ni ileile — 10. Idadi ya sarafu kuongezeka haimaanishi umekuwa tajiri. Katika jamii kuna watu wabaya wanaoonyesha pesa nyingi zilizogawanywa vipande vidogo na kujaribu kumdanganya mtoto: 'Nakupa hizi zote, badilisha na ile sarafu moja kubwa.' Usidanganywe na muonekano — kuwa na jicho linalokokotoa thamani halisi." },
  { id:75, topic:"Ugunduzi wa Sufuri", emoji:"0️⃣",
    question:"Kulikuwa na mayai 3 kwenye kapu. Yote 3 uliyatumia katika kupika. Sasa ukielezea idadi ya mayai kwenye kapu kwa namba, ni ipi?",
    choices:["1","2","3","0 (sufuri)"],
    answerIndex:3,
    explanation:"Mojawapo ya uvumbuzi mkubwa zaidi katika hisabati ni namba '0 (sufuri)'. Sufuri haimaanishi tu kwamba hakuna namba; ni namba maalum na yenye hekima, iliyoundwa ili — kama namba nyingine yoyote — kurekodi na kuelezea kwa usahihi hali ya 'hakuna kitu kilichopo hapo, ni tupu'. Toa 3 kutoka 3 na baki ni 0. Kwa sababu ya sufuri hii, tunaweza kuwaambia wenzetu walio mbali kwa usahihi, kwa maandishi au namba, kuhusu dharura kama 'chakula kimekwisha kabisa' au 'hakuna mzigo wowote', na kuomba msaada." },
  { id:76, topic:"Kuweka Makundi", emoji:"🐶",
    question:"Swali la kuweka maneno makundi. 'Mbwa, paka, ndege, mjusi' — wote wanaingia katika kundi gani kubwa la jumla (wanawekwa katika kundi gani)?",
    choices:["Kundi la mimea","Kundi la wanyama","Kundi la samaki","Kundi la binadamu"],
    answerIndex:1,
    explanation:"Hii ni mantiki ya 'uainishaji (kuweka makundi kwa sifa za pamoja)'. Mbwa, paka, ndege na mjusi, kila mmoja ana umbo na namna ya kuishi tofauti, lakini wana sifa kubwa ya pamoja: 'viumbe hai vinavyojisogeza vyenyewe na kula chakula'. Kwa hivyo wote wanaingia katika chumba kikubwa kiitwacho 'wanyama'. Kupanga kichwani habari nyingi na vifaa vingi vya dunia — katika makundi makubwa na aina ndogo zaidi — ni silaha yenye nguvu ya kufikiri ili kuelewa kiini cha vitu haraka." },
  { id:77, topic:"Kuhesabu Kinyumenyume", emoji:"⏪",
    question:"Kuna namba fulani (namba ya swali). Ulipoijumlisha '5', jibu likawa '12'. Namba ya awali ilikuwa ngapi?",
    choices:["5","7","12","17"],
    answerIndex:1,
    explanation:"Hili ni fumbo la 'kuhesabu kinyumenyume', ambapo unarudisha wakati nyuma kutoka matokeo ili kupata sababu ya awali. Kama kujumlisha 5 kwenye namba kulitoa 12, basi 'kurudisha nyuma na kutoa ile 5 iliyojumlishwa' kutoka 12 ya mwisho kunafichua namba ya awali. 12 toa 5 ni 7. Maishani tatizo linapotokea, uwezo huu wa 'kurudisha wakati nyuma kutoka matokeo hadi sababu' unakuwezesha kugundua kwa werevu wapi ulikosea, au nini kilivunja kifaa, na kukirekebisha." },
  { id:78, topic:"Kununua kwa Bajeti", emoji:"🛍️",
    question:"Swali la ununuzi! Una 'sarafu 30'. Dukani wanauza kiazi kwa sarafu 10, nyanya kwa sarafu 15, na samaki kwa sarafu 20. Ili kununua sawasawa 'aina 2 za chakula' kwa pesa uliyonayo, utachagua zipi mbili?",
    choices:["Kiazi na nyanya","Nyanya na samaki","Kiazi na samaki","Hakuna jozi ya mbili inayoweza kununuliwa"],
    answerIndex:2,
    explanation:"Hili ni swali la kufikiri ambapo unatafuta mchanganyiko unaotimiza masharti yenye mipaka (bajeti sarafu 30, aina 2 sawasawa). Jumlisha kila bei. Kiazi sarafu 10 jumlisha nyanya sarafu 15 ni sarafu 25, chini ya 30, na pesa inabaki. Nyanya sarafu 15 jumlisha samaki sarafu 20 ni sarafu 35, ambayo inazidi 30 na haiwezi kununuliwa. Kiazi sarafu 10 jumlisha samaki sarafu 20 ni sarafu 30 sawasawa, ambayo inalingana kabisa na pesa uliyonayo. Hivyo jibu sahihi ni mchanganyiko wa kiazi na samaki. Tumia uwezo wa kuchanganya namba kadhaa kichwani na kupanga ili usizidi bajeti yako." },
  { id:79, topic:"Kiasi Hakibadiliki", emoji:"🥤",
    question:"Ulimimina 'maji' yote kutoka glasi ndefu nyembamba hadi sahani bapa pana. Uso wa maji ulienea, lakini 'kiasi cha jumla cha maji (ujazo wake)' kimebadilikaje?",
    choices:["Sahani ni pana zaidi, hivyo kiasi cha maji pia kimeongezeka mara mbili","Glasi ilikuwa ndefu zaidi, hivyo kiasi cha maji kimepungua","Ingawa umbo la chombo limebadilika, kwa kuwa haujamwaga chochote, kiasi cha maji ni 'kilekile kabisa (hakijabadilika)'","Maji yote yametoweka"],
    answerIndex:2,
    explanation:"Hii ni hekima muhimu sana ya 'kuhifadhi' katika sayansi na hisabati. Hata umbo likiwa refu jembamba, au likienea bapa pana, maadamu hauongezi maji mapya kutoka nje wala kumwaga, kiasi cha jumla cha dutu iliyo ndani ni 'kilekile bila shaka' na hakibadiliki. Katika jamii kuna watu wanaomimina juisi kwenye chombo kifupi kinachoonekana pana na kujaribu kukudanganya kwa muonekano: 'Tazama, imeongezeka sana, ni faida iliyoje!' Usidanganywe na umbo — kuwa na jicho linaloona kiini cha kilichomo." },
  { id:80, topic:"Kufikiri Kuhusu Uwezekano", emoji:"🔴",
    question:"Swali la uhakika. Kuna mfuko usioonekana ndani kabisa wenye 'mawe mekundu' 5 tu. Unapoingiza mkono na kutoa jiwe 1, je 'jiwe la buluu' linaweza kutoka?",
    choices:["Wakati mwingine moja linaweza kutoka kwa bahati","Kwa kuwa mfuko una mawe mekundu tu, jiwe la buluu kutoka ni 'haiwezekani 100% (uwezekano sufuri)'","Ukiutikisa mfuko kwa nguvu sana, moja litatoka","Usiku ukiingia linageuka kuwa jiwe la buluu"],
    answerIndex:1,
    explanation:"Hili ni swali la kufikiri kimantiki kuhusu uhakika (uwezekano) wa mambo kutokea. Mfuko una 'mawe mekundu' tu tangu mwanzo. Isipokuwa uchawi utokee, hakuna sababu yoyote ya 'jiwe la buluu' lisilokuwepo ndani kutoka. Hivyo nafasi ya jiwe la buluu kutoka ni 'haiwezekani 100%', hilo ndilo jibu. Duniani kuna watu wanaojaribu kuwadanganya wengine kwa uongo kama 'ukiomba, chakula kitatokea kutoka katika hakuna kitu'. Weka katika ubongo wako mantiki baridi ya sayansi: kisicho na sababu hakitatokea kamwe kama matokeo." },
  { id:81, topic:"Kazi na Mgawanyo", emoji:"👷",
    question:"Ni sababu gani kuu inayowafanya watu wazima duniani kote kufanya 'kazi (utumishi)' mbalimbali — kulima mashamba, kujenga majengo, kutengeneza vifaa?",
    choices:["Ili mtu mmoja peke yake aishi kwa anasa na kujivuna","Kwa sababu binadamu hawezi kuishi peke yake; kwa kila mmoja kufanya kazi tofauti na kusaidiana (mgawanyo wa kazi), jamii nzima inaweza kuishi kwa usalama","Tu kwa sababu wanataka kuusogeza mwili na kucheza","Wanasogea tu kwa sababu mtu aliamuru, bila chaguo"],
    answerIndex:1,
    explanation:"Binadamu ni viumbe dhaifu, bila meno makali kama simba, ambao wangefa kwa baridi bila nguo. Zaidi ya hayo, ni vigumu kabisa kwa mtu mmoja kujenga nyumba yake mwenyewe, kulima ngano yake mwenyewe, na kutengeneza dawa yake mwenyewe — muda hautoshi. Ndiyo maana binadamu walivumbua hekima ya kijamii ya 'mgawanyo wa kazi', ambapo wote wanagawana kazi tofauti. Seremala anajenga nyumba, mkulima analima chakula, daktari anaponya magonjwa. Kiini cha kazi ni kutatua matatizo ya mtu ndani ya jamii na kushikilia kwa upole maisha ya kila mmoja kwa bidhaa na huduma." },
  { id:82, topic:"Mwanzo wa Pesa", emoji:"🐚",
    question:"Ni faida gani kubwa zaidi binadamu wa kale walipoacha kubadilishana bidhaa moja kwa moja na kuanza kutumia 'pesa (sarafu)' za makombe au chuma?",
    choices:["Kwa sababu kuwa na pesa kunawafanya wezi waache kukushambulia","Kwa sababu hata kati ya 'watu wanaotaka kubadilishana vitu tofauti', kuweka pesa katikati kunawezesha kubadilishana kwa haki na kwa urahisi wakati wowote kwa kile unachotaka","Kwa sababu pesa inakuwa lishe ikiliwa","Kwa sababu pesa zimetapakaa kila mahali bila mwisho"],
    answerIndex:1,
    explanation:"Katika maisha ya 'kubadilishana bidhaa', hata ukitaka kubadilisha samaki wako na nguo za mtu, biashara inashindikana kama mtu huyo hataki samaki. Pia, samaki huoza haraka, hivyo thamani yake haiwezi kuhifadhiwa. Ndiyo maana binadamu walitengeneza chombo cha uaminifu ambacho wote wanakubali thamani yake kwa pamoja: 'pesa (sarafu)'. Ukibadilisha samaki kuwa pesa mara moja, unaweza kuihifadhi bila kuoza, na baadaye katika mji mwingine, wakati wowote unapohitaji, kununua nguo au dawa, chochote. Pesa ni hekima bora, iliyovumbuliwa ili watu duniani kote wasaidiane kwa urahisi bila usumbufu." },
  { id:83, topic:"Ahadi za Wote", emoji:"📜",
    question:"Katika uwanja au barabara inayotumiwa na wote, kwa nini kuna 'kanuni (ahadi za jamii)' kama 'usitupe taka' na 'heshimu zamu'?",
    choices:["Kuwakemea watoto na kuwanyang'anya uhuru wao","Kwa sababu wote wanapofuata kanuni, ugomvi na ajali huzuiwa, na wote wanaweza kuishi kwa usawa, kwa upole na kwa usalama","Kufunga uwanja ili hakuna autumie","Kuwanufaisha watu muhimu fulani tu"],
    answerIndex:1,
    explanation:"Kanuni na sheria (ahadi) hazikutengenezwa kumfunga mtu na kumnyima uhuru. Ingekuwaje kama hakuna kanuni kabisa na wote wakitenda 'wapendavyo'? Uwanja ungejaa taka na kuzaa magonjwa, magari na vyombo vingegongana barabarani, na mwenye nguvu angemnyang'anya dhaifu chakula chake — dunia ya kutisha ya ukatili. Kanuni ni 'mkataba wa upole ambao wote wamekubaliana' wa kulinda usalama wa wote. Kufuata kanuni vizuri kunahusiana moja kwa moja na kulinda uhuru na usalama wako mwenyewe." },
  { id:84, topic:"Mzunguko wa Maji", emoji:"🔄",
    question:"Baada ya 'maji ya mvua' kuanguka kutoka angani na kupenya ardhini, yanafanya safari gani ili kurudi angani tena?",
    choices:["Yanabaki yamejaa chini ya ardhi na hayasogei tena kamwe","Yanakusanyika kuwa mito na kutiririka baharini, yanavukiza kwa joto la jua kuwa mawingu, na yanaanguka tena kama mvua (mzunguko wa maji)","Yanaruka moja kwa moja angani ya mbali","Binadamu wanayanywa yote na ndio mwisho"],
    answerIndex:1,
    explanation:"Maji yote duniani, tangu mamia ya mamilioni ya miaka iliyopita, yamekuwa yakisafiri tena na tena duniani kote yakibadilisha umbo. Hii inaitwa 'mzunguko' wa maji. Mvua iliyoanguka milimani inatengeneza mito, inaenda baharini ikinyweshea uhai wa viumbe, inapashwa joto na jua kuwa mvuke usioonekana unaopanda angani, inapoa kuwa mawingu, na inaanguka tena kama mvua. Maji tunayonywa leo ni hazina ileile ya sayari ambayo dinosaria walinywa zamani. Kulinda mfumo wa asili wa maji safi yanayozunguka dhidi ya uchafuzi kunahusiana na kulinda uhai wa binadamu wote." },
  { id:85, topic:"Mimea na Oksijeni", emoji:"🌳",
    question:"Ile 'miti na nyasi (mimea)' mingi msituni, inafanya kazi gani ya ajabu ili sisi binadamu na viumbe vingine hai tuweze kuishi?",
    choices:["Kazi ya kugiza ardhi na kuifanya baridi","Kwa kutumia mwanga wa jua na maji, kazi ya kutengeneza hewani ile 'oksijeni safi' ambayo binadamu na wanyama wanahitaji bila shaka ili kupumua","Kazi ya kusimamisha upepo wote na kuiongeza joto dunia","Hawafanyi chochote"],
    answerIndex:1,
    explanation:"Binadamu na wanyama wanavuta 'oksijeni' iliyomo hewani na kupumua nje 'kaboni dioksidi' badala yake. Kama hakungekuwa na mimea duniani, oksijeni hewani ingekwisha haraka na viumbe vyote hai vingekosa hewa na kufa. Miti na nyasi za msituni zinatumia mwanga wa jua kuvuta kaboni dioksidi, na kutengeneza bila kikomo, kila siku, ile 'oksijeni' safi tunayohitaji kuishi. Zaidi ya hayo, mizizi ya mimea inashika udongo kwa nguvu na pia inafanya kazi ya kuzuia maporomoko ya ardhi milimani. Kulinda misitu ni kulinda kiwanda cha hewa cha dunia." },
  { id:86, topic:"Uchavushaji na Wadudu", emoji:"🦋",
    question:"Wadudu kama 'nyuki na vipepeo' wanaokuja kwenye maua, wanatekeleza jukumu gani muhimu la kuwasaidia mimea kuacha kizazi?",
    choices:["Jukumu la kung'oa majani yote ya ua na kulifanya linyauke","Badala ya kunywa asali ya ua, jukumu la kushikamanisha 'chavua' kwenye miguu na mwili na kuipeleka kwa maua ya mbali, na kusaidia kuundwa kwa matunda na mbegu (uchavushaji)","Jukumu la kulikasirisha ua ili liote miiba","Wanacheza tu na hawana faida yoyote"],
    answerIndex:1,
    explanation:"Mimea, ambayo haiwezi kusogea hatua moja kutoka ardhini, haiwezi kuongeza jamii yake (mbegu) yenyewe. Hapa ndipo wadudu kama nyuki na vipepeo wanang'ara. Wanaruka kutoka ua hadi ua ili kula asali tamu, na ile 'chavua' iliyoshikamana mwilini inapopelekwa kwa ua jingine, mimea hatimaye inaweza kuunda kwa usalama 'mbegu na matunda'. Hii inaitwa 'uchavushaji'. Kama wadudu wangetoweka, mimea ya dunia isingeweza kuzaa matunda, na misitu na mashamba vingetoweka. Katika asili, wote wanaishi wakisaidiana bila hata kutambua." },
  { id:87, topic:"Kutupa Taka Ovyo", emoji:"🗑️",
    question:"Nini kinatokea ukitupa mabaki ya chakula chako na vifaa usivyovitumia tena (taka) moja kwa moja mitoni au ardhini?",
    choices:["Taka inayeyuka yenyewe na kugeuka kuwa pesa","Maji na udongo vinachafuka, vijidudu vyenye sumu na sumu vinaenea, samaki wa mtoni na wanyama wa msituni wanakufa, na kwa kuzunguka kurudi, hata maji ya kunywa na chakula cha binadamu vinakuwa hatari","Ardhi inakuwa imara zaidi na ni rahisi kujenga nyumba","Hakuna kinachobadilika"],
    answerIndex:1,
    explanation:"Kutupa taka yako ovyo karibu ni sawa na kutawanya sumu ndani ya nyumba unayoishi mwenyewe. Plastiki na taka fulani hazitoweki kwa nguvu ya asili hata baada ya mamia ya miaka. Zikisombwa na mvua zinachafua mito na bahari; samaki wanaozila wanaugua; na binadamu wakila samaki hao, hatimaye zinarudi kama 'sumu kali' kwa mwili wako mwenyewe na afya ya watoto wako. Dunia nzima imeunganishwa. Kuchukua jukumu la kupanga na kusimamia vizuri ulichotumia ni upole wa jamii unaolinda uhai wa baadaye." },
  { id:88, topic:"Kurekebisha na Kutumia Tena", emoji:"🔨",
    question:"Shoka, kisu, au nguo ya thamani nyumbani inapovunjika au kuchanika kidogo, ni jibu lipi lenye hekima zaidi?",
    choices:["Kuitupa mara moja na kunyang'anya mtu mpya","Kutumia hekima yako 'kurekebisha (kushona)', na kuendelea kutumia kifaa kilekile kimoja kwa uangalifu kwa muda mrefu","Kukilazimisha kufanya kazi kikiwa kimevunjika na kupata jeraha kubwa","Kujifanya hukukiona na kukiacha"],
    answerIndex:1,
    explanation:"Kutengeneza vifaa kunahitaji kutumia kwa wingi 'rasilimali' za thamani za dunia, kama miti, chuma, nyuzi za mimea. Hizi si za milele. Ukitupa vitu kila vinapovunjika kidogo, rasilimali za dunia zitakwisha na hakuna atakayeweza kutengeneza vifaa tena. Hekima ya ajabu ya binadamu imeendeleza ujuzi wa 'kurekebisha na kutumia tena' kilichovunjika. Kurekebisha vifaa na kuvitumia kwa uangalifu kwa muda mrefu ni ujuzi muhimu wa maisha wa kulinda rasilimali za dunia, kupunguza matumizi yasiyo na maana, na kuishi kwa werevu na kujitegemea." },
  { id:89, topic:"Kukubali Tofauti", emoji:"🤝",
    question:"Dunia imejaa watu ambao 'lugha', 'rangi ya ngozi', na 'nyumba wanayoishi' ni tofauti kabisa na zako. Ni mtazamo gani wa moyo muhimu zaidi ili kupatana na kushirikiana nao?",
    choices:["Kutafuta pale wanapotofautiana na wewe, na kuwanyanyasa au kuwatenga","Hata muonekano na lugha vikitofautiana, kukubali tofauti za kila mmoja kama 'binadamu mwenye uhai wa thamani' yuleyule, na kutendeana kwa upole na heshima","Kujivuna kwa sauti kubwa kwamba kundi lako mwenyewe ni bora","Kwa hofu, kuwashambulia wote kana kwamba ni maadui"],
    answerIndex:1,
    explanation:"Kulingana na nchi waliyozaliwa na mazingira waliyokulia, watu wanatofautiana kabisa katika lugha wanayozungumza, chakula wanachokula, na utamaduni wanaothamini. Lakini ni upi bora au upi mbaya — hilo halipo kamwe. Kumnyanyasa au kugombana na mtu tu kwa sababu ni 'tofauti' ni kitendo cha kipumbavu zaidi, kinachovunja jamii na kuwafanya wote wasiwe na furaha. Tofauti ni fursa ya ajabu ya kujifunza hekima mpya. Kukubali tofauti za kila mmoja, na kuwa na moyo wa upole unaosaidia ng'ambo ya mipaka mtu anapokuwa shidani, ndio hatua ya kwanza ya kumaliza vita na umaskini duniani." },
  { id:90, topic:"Rasilimali za Wote", emoji:"⛲",
    question:"Kwa nini hupaswi kumiliki peke yako, au kuchafua, 'kisima cha pamoja' au 'maji safi' ya kijiji?",
    choices:["Kwa sababu maji ya kisima yanaogopa na kukauka","Kwa sababu kunyang'anya rasilimali ya wote (mali ya umma) kunawafanya wengine washindwe kunywa na kupoteza maisha, na mfumo wa ushirikiano wa jamii nzima unavunjika","Kwa sababu kuna hazina iliyofichwa ndani ya kisima","Hakuna sababu maalum"],
    answerIndex:1,
    explanation:"Mali ya pamoja ambayo wote wanaitumia ili kuishi — kama mito, misitu, na visima — inaitwa 'mali ya umma'. Kama mtu mwenye nguvu fulani anaimiliki peke yake au anaichafua apendavyo, watu dhaifu wengi wasioweza kuishi wanazaliwa, na uwiano wa kijiji au mji mzima unavunjika na wote wanaangamia. Kilicho cha wote kinatumika kidogo kidogo, kwa haki na kwa uangalifu, kwa kanuni ambazo wote wanaamua pamoja. Jamii ambapo hekima hii ya 'kushirikiana (msaada wa umma na wa pamoja)' inafanya kazi ni tajiri kweli — dunia ya upole (ustawi) ambapo kila mtu anaweza kuishi muda mrefu kwa amani." },
  { id:91, topic:"Kujifunza Kutoka Historia", emoji:"📚",
    question:"Kuna maana gani ya kusoma, kupitia vitabu na hadithi, matukio ya zamani na 'kumbukumbu za mafuriko makubwa' walizopitia babu na bibi?",
    choices:["Kusikia hadithi za zamani za kutisha na kuishi tu kila siku ukitetemeka kwa hofu","Kujifunza 'hekima ya historia' — watu wa zamani walifanya makosa gani na walivukaje hatari — na kulinda maisha yako ya baadaye kwa usalama","Kuwasema vibaya watu wa zamani","Kujifanya umesoma kwa kusoma kitabu"],
    answerIndex:1,
    explanation:"Maana halisi ya kusoma historia si kukariri majina ya watu wa zamani. Ni kupokea 'ujumbe wa uhai na kifo (data ya uzoefu) ambao binadamu wa zamani waliuacha kwa ajili yetu'. Kama watu wa kale waliacha kumbukumbu inayosema 'mara moja kila miaka mia mto huu unafurika hadi urefu wa lile jiwe, hivyo usijenge nyumba hapa', tunaweza kuepuka kujenga mahali paleile na maisha yetu yanaokolewa. Historia ni mwongozo wenye nguvu zaidi ambao binadamu wameujenga kutoka makosa makumi ya maelfu. Jifunze hekima ya wazee na epuka kwa werevu majanga ya baadaye." },
  { id:92, topic:"Safari ya Chakula", emoji:"🚜",
    question:"'Chakula' unachokula mbele yako kila siku, kama wali na mkate, kimefanya safari gani kabla ya kufika mdomoni mwako?",
    choices:["Mtu fulani mahali fulani alisoma uchawi, akakifanya kitokee sahanini papo hapo","Kimefika kupitia 'kazi' ya watu wengi: mkulima alilima shamba kila siku, mwingine akakibeba kutoka mbali, muuzaji akakiuza, na mtu nyumbani akakipika","Kilichipuka kutoka ardhini chenyewe","Kilianguka kutoka angani"],
    answerIndex:1,
    explanation:"Nyuma ya chakula unachokiona kuna 'mbio za kupokezana za mamia ya watu (kazi)' zisizoonekana. Mkulima aliyelima udongo, akapanda mbegu, na kukikuza huku akiwa na wasiwasi kuhusu hali ya hewa kila siku. Mtu aliyekipakia kwenye gari zito au lori na kukibeba njia ndefu. Mtu aliyekiuza kwa haki sokoni. Na mtu aliyekipika kwa moyo wote kwa ajili yako. Kuthamini chakula ni kushukuru na kuheshimu wakati na juhudi (nguvu ya uhai) ya kila mmoja wa watu hao. Kuza moyo wa upole unaokula kwa shukrani na haupotezi chochote." },
  { id:93, topic:"Kushiriki Hatari", emoji:"🚧",
    question:"Msituni au barabarani, unapata 'mahali pa hatari ambapo ardhi imeporomoka vibaya, hivyo kuingia kunamaanisha kuanguka shimoni na kuumia vibaya'. Ni kitu gani cha kwanza cha kufanya?",
    choices:["Kwa kuwa inatosha wewe peke yako kujua, kuondoka kimya kimya","Ili marafiki au wanakijiji watakaokuja baadaye wasianguke na kuumia, kuweka 'alama (kizuizi)' kwa tawi kubwa, au kuwaambia mara moja watu wazima na watu wa karibu ili kushiriki hatari","Kutupa mawe mengi shimoni","Kucheza fishichio karibu na shimo"],
    answerIndex:1,
    explanation:"Kuijulisha jamii nzima kuhusu hatari uliyoipata, si kujiokoa wewe tu, kunaitwa 'kushiriki hatari'. Ukiondoka kimya kimya, mtoto mdogo atakayekuja akikimbia baadaye, au babu anayetembea barabarani usiku, anaweza kuanguka shimoni bila kujua na kupata jeraha la kifo. Kuwaambia wengine kuhusu hatari ni kitendo cha ajabu cha ustawi kinachookoa maisha ya mwingine kwa njia isiyo ya moja kwa moja kutoka ajali ya baadaye ambayo bado haijatokea. Kuwa kiongozi wa upole anayetumia hekima kwa ajili ya wote." },
  { id:94, topic:"Kuchakata Tena", emoji:"♻️",
    question:"Vitambaa vibovu visivyotumika tena, vifaa vilivyovunjika, na vyombo vya plastiki, badala ya kuvichoma au kuvizika kama taka, kuvigeuza kuwa malighafi ya vifaa vipya na kuvizaa upya — mfumo huu unaitwaje?",
    choices:["Kutupa taka","Kuchakata tena (matumizi upya ya rasilimali)","Kubadilishana bidhaa","Usanisinuru"],
    answerIndex:1,
    explanation:"Badala ya kutupa tu taka iliyotumika kwenye pipa, ujuzi wa kuiyeyusha tena au kuivunja vipande vidogo na kuigeuza, kutoka sufuri, kuwa 'malighafi' ya nguo, ndoo, na vifaa vipya unaitwa 'kuchakata tena (matumizi upya ya rasilimali)'. Ikitumika vizuri, kuchakata tena kunafanya usihitaji tena kuchimba milima ya dunia kwa ajili ya malighafi mpya, hivyo unaweza kudumisha maisha tajiri milele bila kuidhuru sayari. Ni hekima ya kisasa ya kuthamini rasilimali za asili na kujenga dunia endelevu (inayodumu)." },
  { id:95, topic:"Jinsi Misimu Inavyokwenda", emoji:"🌎",
    question:"Duniani, misimu ya joto ambapo mimea inakua na misimu ya baridi ambapo theluji inaanguka (mabadiliko ya misimu), inarudi kila mwaka kwa kanuni isiyobadilika. Kwa nini?",
    choices:["Kwa sababu dunia inapozunguka jua kwa mwaka mmoja, mhimili wa dunia umeinama kidogo upande","Kwa sababu jua linabadilisha mng'ao wake kila siku kulingana na hisia zake","Kwa sababu mawingu yanafukuzana bila kukoma kuzunguka dunia","Kwa sababu mungu wa misimu anaibadilisha kulingana na hisia zake"],
    answerIndex:0,
    explanation:"Dunia ina mabadiliko ya misimu kama 'masika, kiangazi, vuli, baridi', na hili lina sababu ya kisayansi 100%. Nyota duara iitwayo dunia inazunguka jua mara moja kwa mwaka mmoja (mzunguko), na inapofanya hivyo, kichwa cha dunia (mhimili wake) kinabaki kimeinama 'kidogo upande'. Kwa hiyo, wakati wa mzunguko, kwa zamu zinatokea 'wakati ambapo mwanga mwingi wa jua unagusa (kiangazi)' na 'wakati ambapo mwanga unagusa kwa mteremko na kidogo (baridi)', hivyo misimu inarudi kama kalenda inavyosema. Elewa kanuni zisizobadilika za ulimwengu na zitumie katika kupanga maisha yako." },
  { id:96, topic:"Mifugo na Kuishi Pamoja", emoji:"🐄",
    question:"Kwa nini binadamu wa kale waliwafuga ng'ombe, farasi, mbwa na wanyama wengine wa porini ili kuishi pamoja kama 'mifugo'?",
    choices:["Ili kukimbia mashindano na kucheza na wanyama","Kwa kusaidiana: kuwafanya wavute mikokoteni mizito ambayo binadamu hawawezi kuisogeza na kushiriki maziwa na ngozi yao, badala ya kuwapa wanyama chakula na nyumba salama (kuishi pamoja)","Kuwafungia wanyama chumbani na kuwatawala","Hakuna sababu yoyote"],
    answerIndex:1,
    explanation:"Mfumo wa 'mifugo', ambapo binadamu wanafuga wanyama na kuishi pamoja nao, ni hekima ya ajabu ya 'kuishi pamoja (uhusiano wa manufaa)' ya kuokoka katika asili kubwa kwa kufidiana udhaifu. Kwa kukopa nguvu kubwa ya farasi na ng'ombe, binadamu wanaweza kulima shamba pana papo hapo na kubeba mamia ya kilo za mizigo. Badala yake, binadamu wanajenga vibanda salama ambapo wanyama hawashambuliwi na wanyama wa porini wala nyama, na kuandaa chakula kitamu na maji kila siku ili kutunza uhai wao. Huruma kwa viumbe hai na hekima ya kuwatunza vimetajirisha maisha ya binadamu." },
  { id:97, topic:"Kuunganisha Nguvu", emoji:"🗿",
    question:"'Jiwe kubwa sana' ambalo halisogei hata milimita moja hata mtu mmoja akilisukuma kwa nguvu kiasi gani, limefunga barabara. Ni njia gani yenye hekima zaidi ya kulisogeza jiwe hili?",
    choices:["Kulipiga jiwe peke yako kila siku na kulia","Kukusanya wenzako wengi, kutumia mtaimbo mrefu, na kuwafanya wote waunganishe nguvu kwa wakati uleule kwa ishara ya pamoja 'Moja, mbili, vuta!' (kufanya kazi pamoja)","Kusubiri kimya jiwe lijiondoe lenyewe","Kulipigia jiwe kelele kwa sauti kubwa"],
    answerIndex:1,
    explanation:"Nguvu ya mtu mmoja ina kikomo cha kimwili kisichobadilika. Lakini nguvu halisi ya binadamu haiko katika unene wa misuli, bali katika uwezo wa ubongo wa 'kuunganisha nguvu (kushirikiana)' na binadamu wengine. Watu kumi wakisukuma kila mmoja peke yake hawalisogezi jiwe, lakini wote wanapojikita nguvu zao katika 'wakati uleule kabisa' kwa ishara 'Moja, mbili, vuta!' (kwa kuoanisha) na kutumia kanuni ya mtaimbo, jiwe kubwa lisilowezekana kwa mtu mmoja linaviringika na kusogea kwa urahisi wa kushangaza. Ushirikiano ndio nguvu kubwa zaidi ya binadamu." },
  { id:98, topic:"Kushindwa Ni Mafunzo", emoji:"🎯",
    question:"Katikati ya kazi, kusoma au swali, ulikosea — 'kushindwa'. Wakati huo, ni njia gani sahihi ya kutumia moyo wako ili ukue zaidi?",
    choices:["Kusema uongo kwamba huwezi kushindwa kamwe, na kuficha kosa","Kufikiri kwamba 'kushindwa ni fursa bora ya kujifunza na kunamtokea yeyote', kufikiri kwa nini ulikosea, na kukitumia mara ijayo","Kukata tamaa ukijiona mtu asiyefaa na kutojaribu tena kamwe","Kukasirika na kusema kushindwa ni kosa la wengine"],
    answerIndex:1,
    explanation:"Katika kuishi, kukosea na kushindwa si aibu wala si jambo baya kamwe. Hata wanasayansi na madaktari wenye hekima zaidi duniani walifanya makosa makumi ya maelfu mara kwa mara ili kufikia ugunduzi wao wa ajabu. Kupoteza zaidi ni kuficha kushindwa, au kulaumu wengine, na kuacha kujifunza. Kushindwa kunamaanisha umepata data moja ya thamani: 'njia hii haifanyi kazi'. Gundua sababu kwa utulivu, na ukuze uwezo wa kubuni hatua yako ijayo (ustahimilivu)." },
  { id:99, topic:"Kuhakiki Uvumi", emoji:"🔍",
    question:"Ulisikia uvumi kutoka kwa mtu: 'Inasemekana katika mto ule yanabubujika maji ya kichawi yanayoponya ugonjwa wowote papo hapo.' Utafanya nini?",
    choices:["Kwa kuwa ni habari ya ajabu, kuamini mara moja na kunywa maji hayo kwa wingi","Kutoamini uvumi 100% kama ulivyo; kutumia maarifa ya watu wazima wa kuaminika na vitabu, kuhakiki vizuri mwenyewe kama kuna ushahidi halisi wa kisayansi","Kueneza kwa marafiki wote uongo kwamba watakufa wasiponywa haraka","Kuogopa na kutotoka chumbani kamwe tena"],
    answerIndex:1,
    explanation:"Jamii imejaa uvumi usio na msingi (bila ushahidi), na habari mbaya (upotoshaji) zinazoenezwa kwa makusudi ili kuwasumbua watu au kuwadanganya wachukue pesa. Kutenda kwa kumeza maneno 100% kama yalivyo ni hatari kama kupanda gari lisilo na breki. Wakati wowote jambo linapoonekana la ajabu au geni, daima simama kidogo na ufikiri: 'Je ni kweli? Kuna ushahidi imara?' Hekima ya kuhakiki ukweli kwa data ya vitabu na kwa watu wa kuaminika wenye uzoefu (uelewa wa vyombo vya habari) inakulinda dhidi ya mitego." },
  { id:100, topic:"Ngao ya Hekima", emoji:"🛡️",
    question:"Katika programu hii 'Wise World 2', umejifunza mengi kuhusu muundo wa mwili, kanuni za asili, na uhusiano wa jamii. 'Lengo halisi' ni nini?",
    choices:["Kukusanya pointi za uzoefu za mchezo (EXP) na kuwa mtu muhimu zaidi duniani","Kuhifadhi kichwani mwako 'ngao ya juu kabisa na yenye nguvu zaidi ya hekima', ili katika mazingira yoyote usidanganywe, uishi kwa werevu na kujitegemea, na — huku ukilinda haki na uhai wa wengine — ujenge kwa mikono yako mwenyewe 'dunia ya upole na salama' ya kuishi","Kumiliki pesa zote na kuwaamuru wengine wakutii","Kujibu maswali yote sawa na kumaliza mchezo"],
    answerIndex:1,
    explanation:"Vizuri sana! Swali la 100 la kukumbukwa sasa limekamilika. Hekima yote uliyojifunza katika programu hii si ya kuwashinda wengine na kujivuna, wala si ya mtu mmoja peke yake kuishi kwa anasa. Ni ili popote ulipo duniani — hata katika mazingira magumu yasiyo na watu wazima wa kukusaidia — uweze kufikiri kisayansi kwa akili yako mwenyewe ili kulinda uhai wako, na kuokoka kwa kujitegemea bila kudanganywa na watu wabaya (kuwezeshwa). Na ni nuru ya kutumia hekima hii ya werevu kuwasaidia watu walio shidani karibu yako, na — ng'ambo ya mipaka na lugha — kuendelea kuzungusha mwenyewe, pamoja na wote, 'uchumi na dunia ya ustawi ya upole na salama'. Hekima imara uliyojifunza italinda maisha yako tangu sasa na itakuwa hirizi inayoangaza kwa upole mustakabali wa dunia. Watu wote duniani kote wanashangilia kwa moyo wote mafanikio ya safari yako ya kujifunza!" }
];
